        /* --- SWISS ISLAND CONTAINER --- */
        .swiss-island {
            --spring-easing: cubic-bezier(0.19, 1, 0.22, 1);
            position: relative;
            background-color: #1e1e2e;
            color: #ffffff;
            overflow: hidden;
            z-index: 50;
            transition: width 0.6s var(--spring-easing), height 0.6s var(--spring-easing), border-radius 0.6s var(--spring-easing), transform 0.2s ease, box-shadow 0.6s ease;
            box-shadow: 0 4px 15px rgba(0, 0, 0, 0.5);
            border: 1px solid #3f3f5a;

            --mouse-x: 50%;
            --mouse-y: 50%;
        }

        /* States */
        .swiss-island.collapsed { width: 240px; height: 60px; border-radius: 999px; cursor: pointer; }
        .swiss-island.collapsed:hover { transform: scale(1.05); }
        .swiss-island.collapsed:active { transform: scale(0.95); }
        .swiss-island.expanded { width: 100%; height: 680px; border-radius: 32px; cursor: default; }

        /* --- BUBBLE TRIGGER ZONE --- */
        .bubble-trigger-zone { position: absolute; top: 120px; left: 30px; right: 30px; bottom: 150px; z-index: 15; cursor: pointer; }

        /* --- SPEECH BUBBLE STYLES --- */
        .speech-bubble {
            position: absolute;
            padding: 14px 20px;
