        .speech-bubble.fading { animation: bubbleDissolve 1.5s ease-out forwards; }

        @keyframes bubblePop {
            from { opacity: 0; transform: scale(0.5) translateY(15px) rotate(-5deg); }
            to { opacity: 1; transform: scale(1) translateY(0) rotate(0deg); }
