<!DOCTYPE html>
<html lang="vi-VN">
<head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>Bộ chọn nhánh Dệt Mộng</title>
    <!-- Đồng bộ Font chữ với hệ sinh thái Tawa -->
    <link href="https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800&family=Georgia&display=swap" rel="stylesheet">
    <style>
        :root {
            --font-main: 'Nunito', system-ui, -apple-system, sans-serif;
            --font-serif: 'Georgia', serif;
        }

        body {
            margin: 0; padding: 0; max-width: 100%; overflow-x: hidden; background: transparent !important;
        }

        /* Ẩn các phần không cần thiết của SillyTavern và khu vực tham số cấu hình */
        .branch-selector .mermaid, .branch-selector .mermaid * { display: none !important; }
        #raw-options-data, #raw-options-data a { display: none !important; }

        /* --- Thành phần cơ bản cốt lõi --- */
