    <script>
        document.addEventListener("DOMContentLoaded", function () {
            const body = document.body;
            let styleName = 'v2'; // Kiểu mặc định Tawa

            // Cố gắng tự động nhận diện style từ SillyTavern Presets
            try {
                const TH = window.TavernHelper || window.parent.TavernHelper;
                if (TH) {
                    const presetName = TH.getLoadedPresetName();
                    const presetInUse = TH.getPreset(presetName);
                    if (presetInUse) {
                        const regexes = presetInUse.extensions.regex_scripts || [];
                        const allEnabledNames = [...regexes].filter(r => r && r.enabled).map(r => r.script_name || '');
                        if (allEnabledNames.some(name => name.includes("novel_title mới 3"))) styleName = 'ao3';
                        else if (allEnabledNames.some(name => name.includes("novel_title mới 2"))) styleName = 'v1';
                    }
                }
            } catch (e) { console.warn("Lỗi nhận diện Style, áp dụng mặc định V2", e); }

            document.getElementById("selector-wrapper").classList.add('style-' + styleName);

            // Xử lý Giao diện Sáng / Tối
            function applyThemePreference() {
                const key = styleName === 'ao3' ? 'ao3_theme' : styleName === 'v1' ? 'novel_theme_preference' : 'novel_theme_preference_v2';
                const savedPref = localStorage.getItem(key);
                let isDark = (savedPref === 'night');
                if (styleName === 'v2' && !savedPref) isDark = true;

                if (isDark) { body.classList.remove('theme-light'); body.classList.add('theme-dark'); } 
                else { body.classList.remove('theme-dark'); body.classList.add('theme-light'); }
            }

            applyThemePreference();
            window.addEventListener('storage', (e) => {
                if (['ao3_theme', 'novel_theme_preference', 'novel_theme_preference_v2'].includes(e.key)) applyThemePreference();
            });

            // Logic Render các Nút lựa chọn (Options)
            const rawNode = document.getElementById("raw-options-data");
            const root = document.getElementById("options-container");

            if (rawNode && root) {
                root.innerHTML = '';
                const rawText = rawNode.innerHTML.replace(/<br\s*\/?>/gi, '\n').replace(/</g, '<').replace(/>/g, '>');
                const lines = (rawNode.textContent || rawText).trim().split(/\r?\n/).filter(s => s.trim() !== "");

                lines.forEach((line) => {
                    let text = line.trim();
                    const match = text.match(/^([A-Z])\.\s*(.*)$/i);
                    if (match) text = match[2]; // Ẩn chữ cái A. B. C. cho đẹp
                    if (!text) return;

                    const item = document.createElement("div");
                    item.className = "clickable-text";
                    item.setAttribute("data-action", text);

                    const li = document.createElement("li");
                    li.textContent = text;
                    item.appendChild(li);

                    item.addEventListener("click", function (e) {
                        e.stopPropagation();
                        // Reset màu các nút khác
                        root.querySelectorAll('.clickable-text').forEach(el => el.classList.remove('selected'));
                        this.classList.add('selected'); // Highlight nút được chọn

                        const payload = this.getAttribute("data-action");

                        // Gửi chữ vào khung chat của SillyTavern
                        try {
                            const t = window.parent.document.querySelector("#send_textarea");
                            const n = window.parent.triggerSlash;
                            if (t) {
                                const v = t.value ? t.value + "\n" + payload : payload;
                                if (n) n(`/setinput ${v}`); 
                                else { t.value = v; t.dispatchEvent(new Event("input", { bubbles: true })); }
                            } else if (n) { n(`/setinput ${payload}`); }
                        } catch (err) {
                            console.error("Lỗi gửi text vào SillyTavern:", err);
                        }
                    });
                    root.appendChild(item);
                });
            }
        });
    </script>
