<script>
    document.addEventListener('DOMContentLoaded', function () {
        const templateNode = document.getElementById('ao3-raw-data');
        if (!templateNode) return;

        // 1. Trích xuất
        const content = templateNode.innerHTML;
        let rawMuttering = "";
        let rawQuote = "";
        const mutteringMatch = content.match(/<muttering>([\s\S]*)<\/muttering>/i);
        if (mutteringMatch) rawMuttering = mutteringMatch[1].trim();
        const quoteMatch = content.match(/<quote>([\s\S]*)<\/quote>/i);
        if (quoteMatch) rawQuote = quoteMatch[1].trim();

        // 2. Phân tích Markdown kiểu mới
        function parseMarkdown(text) {
            if (!text) return '';

            let lines = text.split('\n');
            let parsedLines = lines.map(function (line) {
                let trimmed = line.trim();
                trimmed = trimmed.replace(/^&amp;gt;/, '&gt;');
                if (trimmed.startsWith('&gt;') || trimmed.startsWith('>')) {
                    let innerText = trimmed.replace(/^(?:&gt;|>)\s*/, '');
                    return '<div class="ao3-quote">' + innerText + '</div>';
                }
                return line;
            });

            let cleanText = parsedLines.join('\n');

            // In đậm
            cleanText = cleanText.replace(/\*\*(.*?)\*\*/g, function (match, content) {
                return '<span class="ao3-strong">' + content + '</span>';
            });

            return cleanText;
        }

        const finalMuttering = parseMarkdown(rawMuttering);
        const finalQuote = parseMarkdown(rawQuote);

        // 4. Lắp ráp đầu ra
        const commentTarget = document.getElementById('comment-body-target');
        const draftTarget = document.getElementById('draft-textarea-target');

        if (commentTarget) commentTarget.innerHTML = finalMuttering;
        if (draftTarget) draftTarget.innerHTML = finalQuote;

        // 5. Logic tương tác UI (Mở/Đóng Khung)
        const summaryBtn = document.querySelector('.ao3-summary-btn');
        const detailsContainer = document.querySelector('.ao3-comments-details');

        if (summaryBtn && detailsContainer) {
            summaryBtn.addEventListener('click', function () {
                detailsContainer.classList.toggle('is-open');
            });
        }
    });
</script>
