        .mp-loading { display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 20px; font-size: 0.85rem; opacity: 0.7; gap: 10px; color: #9ca3af; }
        .mp-loading i { animation: spin 2s cubic-bezier(0.68, -0.55, 0.27, 1.55) infinite; font-size: 1.5rem; }

        input[type=range].mp-slider {
            -webkit-appearance: none; width: 100%; height: 14px; background: transparent; outline: none; cursor: pointer; margin: 0;
            background: #151521; border-radius: 8px; height: 5px; padding: 0; transition: background 0.3s; border: 1px solid #3f3f5a;
        }
        input[type=range].mp-slider::-webkit-slider-runnable-track { width: 100%; height: 5px; border-radius: 3px; }
        input[type=range].mp-slider::-webkit-slider-thumb {
            -webkit-appearance: none; height: 12px; width: 12px; border-radius: 50%; background: #ff7eb3; margin-top: -4.5px; box-shadow: 0 0 6px rgba(255,126,179,0.8); transition: transform 0.2s ease;
        }
        input[type=range].mp-slider:hover::-webkit-slider-thumb { transform: scale(1.4); }

        .mp-controls-row { display: flex; align-items: center; justify-content: space-between; margin-top: 4px; }
        .mp-vol-wrap { display: flex; align-items: center; gap: 10px; width: 55%; color: #9ca3af; }

        .glass-btn {
            appearance: none; border: none; outline: none; cursor: pointer; display: flex; align-items: center; justify-content: center; color: white;
            background: #151521; border: 1px solid #3f3f5a; border-radius: 50%;
            transition: all 0.3s ease; -webkit-tap-highlight-color: transparent;
        }

        .play-btn { width: 40px; height: 40px; padding: 0; overflow: visible; background: linear-gradient(135deg, #a78bfa, #ff7eb3) !important; border: none; box-shadow: 0 4px 10px rgba(0,0,0,0.5); }
        .play-btn svg { width: 18px; height: 18px; display: block; margin: auto; pointer-events: none; }
        .play-btn svg path, .play-btn svg polygon { fill: #ffffff; stroke: none; }
        .glass-btn:hover { transform: translateY(-2px) scale(1.05); box-shadow: 0 6px 15px rgba(255, 126, 179, 0.4); border-color: #ff7eb3; }
        .glass-btn:active { transform: translateY(1px) scale(0.95); }
    </style>
</head>

<body>
    <div id="root"></div>

    <script type="text/babel">
        const { useState, useRef, useEffect } = React;

        const DEFAULT_BG = "https://files.catbox.moe/2s8y4g.gif"; 
        const DEFAULT_NAME = "VŨ TRỤ CỦA TAWA 🌸";
        const SONG_NAME_FROM_STATUS = "$13";

        const parseQuotes = (xmlString) => {
            if (!xmlString || xmlString.startsWith('$')) return [];
            const regex = /<Tuyển tập câu nói>(.*?)<\/Tuyển tập câu nói>/gs;
            const matches = [];
            let match;
            while ((match = regex.exec(xmlString)) !== null) {
                matches.push(match[1].trim());
            }
            return matches;
        };

        const parseSearchHistory = (xmlString) => {
            if (!xmlString || xmlString.startsWith('$')) return [];
            const recordRegex = /<Lịch sử tìm kiếm>(.*?)<\/Lịch sử tìm kiếm>/gs;
            const records = [];
            let recordMatch;
            while ((recordMatch = recordRegex.exec(xmlString)) !== null) {
                const recordContent = recordMatch[1];
                const contentMatch = /<Nội dung>(.*?)<\/Nội dung>/.exec(recordContent);
                const timeMatch = /<Thời gian>(.*?)<\/Thời gian>/.exec(recordContent);
                if (contentMatch && timeMatch) {
                    records.push({
                        content: contentMatch[1].trim(),
                        time: timeMatch[1].trim()
                    });
                }
            }
            return records;
        };

        const CHAR_DIALOGUES = parseQuotes(`$12`);

        const MusicPlayerUI = ({ songData, isLoading, isPlaying, progress, duration, volume, onTogglePlay, onSeek, onVolumeChange }) => {
            const formatTime = (time) => {
                if (isNaN(time)) return "0:00";
                const min = Math.floor(time / 60);
                const sec = Math.floor(time % 60);
                return `${min}:${sec < 10 ? '0' : ''}${sec}`;
            };

            const PlayIcon = () => (
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" style={{ display: 'block', margin: 'auto', marginLeft: '3px' }}>
                    <polygon points="6,4 20,12 6,20" fill="#ffffff" />
                </svg>
            );

            const PauseIcon = () => (
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" style={{ display: 'block', margin: 'auto' }}>
                    <path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z" fill="#ffffff" />
                </svg>
            );

            if (isLoading) {
                return (
                    <div className="mp-loading">
                        <i className="fa-solid fa-music"></i>
                        <span>Tawa đang tìm bài hát nè~ 🎶</span>
                    </div>
                );
            }

            if (!songData || !songData.Url) {
                return (
                    <div className="mp-loading">
                        <i className="fa-solid fa-headphones-simple" style={{animation: 'none'}}></i>
                        <span>Không gian đang hoàn toàn tĩnh lặng... 🌸</span>
                    </div>
                );
            }

            return (
                <div className="mp-container">
                    <div className="mp-vinyl-area">
                        <div className={`mp-vinyl-disc ${isPlaying ? 'spinning' : ''}`}>
                            <div className="mp-vinyl-grooves"></div>
                            <div className="mp-vinyl-label">
                                {songData.Cover && <img src={songData.Cover} alt="cover" />}
                            </div>
                        </div>
                    </div>
                    <div className="mp-interface">
                        <div className="mp-meta">
                            <div className="mp-title">{songData.Name || 'Bản Nhạc Vô Danh'}</div>
                            <div className="mp-artist">{songData.Singer || 'Kẻ Dệt Mộng'}</div>
                        </div>
                        <div className="mp-progress-stack">
                            <div className="mp-time-row">
                                <span>{formatTime(progress)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>
                            <input type="range" className="mp-slider" value={progress} max={duration || 100} onChange={onSeek} onClick={(e) => e.stopPropagation()} />
                        </div>
                        <div className="mp-controls-row">
                            <div className="mp-vol-wrap">
                                <i className="fa-solid fa-volume-low" style={{fontSize: '0.8rem'}}></i>
                                <input type="range" className="mp-slider" min="0" max="1" step="0.05" value={volume} onChange={onVolumeChange} onClick={(e) => e.stopPropagation()} />
                            </div>
                            <button className="glass-btn play-btn" onClick={onTogglePlay} aria-label={isPlaying ? "Tạm dừng" : "Phát"}>
                                {isPlaying ? <PauseIcon /> : <PlayIcon />}
                            </button>
                        </div>
                    </div>
                </div>
            );
        };

        const SwissDynamicIsland = () => {
            const [isExpanded, setIsExpanded] = useState(false);
            const [activeId, setActiveId] = useState(null);

            const [charName, setCharName] = useState(() => {
                try { return localStorage.getItem('dsi_name') || DEFAULT_NAME; } catch (e) { return DEFAULT_NAME; }
            });

            const [bgUrl, setBgUrl] = useState(() => {
                try { return localStorage.getItem('dsi_bg') || DEFAULT_BG; } catch (e) { return DEFAULT_BG; }
            });

            const [bgSaveStatus, setBgSaveStatus] = useState('');

            useEffect(() => { try { localStorage.setItem('dsi_name', charName); } catch (e) {} }, [charName]);

            useEffect(() => {
                if (bgUrl === DEFAULT_BG || bgUrl.startsWith('http')) {
                    try { localStorage.setItem('dsi_bg', bgUrl); setBgSaveStatus('saved'); } 
                    catch (e) { setBgSaveStatus('session-only'); }
                }
            }, [bgUrl]);

            const [bubbles, setBubbles] = useState([]);
            const audioRef = useRef(null);
            const [songData, setSongData] = useState(null);
            const [isLoadingMusic, setIsLoadingMusic] = useState(false);
            const [isPlaying, setIsPlaying] = useState(false);
            const [progress, setProgress] = useState(0);
            const [duration, setDuration] = useState(0);
            const [volume, setVolume] = useState(0.8);
            const [lastSearchedSong, setLastSearchedSong] = useState('');

            const searchAndLoadSong = async (songName) => {
                if (!songName || songName === lastSearchedSong || songName.startsWith('$')) return;
                setIsLoadingMusic(true); setLastSearchedSong(songName);
                try {
                    if (typeof Music !== 'undefined' && Music.SearchMusic) {
                        const result = await Music.SearchMusic(songName);
                        if (result && result.Url) {
                            setSongData(result);
                            if (audioRef.current) { audioRef.current.src = result.Url; audioRef.current.load(); }
                        } else { setSongData(null); }
                    } else { setSongData(null); }
                } catch (error) { setSongData(null); } finally { setIsLoadingMusic(false); }
            };

            useEffect(() => {
                const songName = SONG_NAME_FROM_STATUS;
                if (songName && !songName.startsWith('$')) searchAndLoadSong(songName);
            }, []);

            useEffect(() => {
                const audio = audioRef.current;
                if (!audio) return;
                audio.volume = volume;
                const updateProgress = () => setProgress(audio.currentTime);
                const setAudioDuration = () => setDuration(audio.duration);
                const handleEnd = () => setIsPlaying(false);
                const handleCanPlay = () => setIsLoadingMusic(false);

                audio.addEventListener('timeupdate', updateProgress);
                audio.addEventListener('loadedmetadata', setAudioDuration);
                audio.addEventListener('ended', handleEnd);
                audio.addEventListener('canplay', handleCanPlay);

                return () => {
                    audio.removeEventListener('timeupdate', updateProgress);
                    audio.removeEventListener('loadedmetadata', setAudioDuration);
                    audio.removeEventListener('ended', handleEnd);
                    audio.removeEventListener('canplay', handleCanPlay);
                };
            }, [volume]);

            const togglePlay = (e) => {
                if(e) e.stopPropagation();
                const audio = audioRef.current;
                if (!audio || !songData?.Url) return;
                if (isPlaying) audio.pause(); else audio.play();
                setIsPlaying(!isPlaying);
            };

            const handleSeek = (e) => {
                const audio = audioRef.current;
                if (!audio) return;
                const val = Number(e.target.value);
                audio.currentTime = val; setProgress(val);
            };

            const handleVolume = (e) => {
                const newVol = Number(e.target.value);
                if (audioRef.current) audioRef.current.volume = newVol;
                setVolume(newVol);
            };

            const handleMouseMove = (e) => {
                if (isExpanded) return;
                const rect = e.currentTarget.getBoundingClientRect();
                const x = e.clientX - rect.left;
                const y = e.clientY - rect.top;
                e.currentTarget.style.setProperty('--mouse-x', `${x}px`);
                e.currentTarget.style.setProperty('--mouse-y', `${y}px`);
            };

            const handleTriggerClick = (e) => {
                if (!isExpanded) return;
                const triggerZone = e.currentTarget;
                const rect = triggerZone.getBoundingClientRect();
                const x = e.clientX - rect.left + triggerZone.offsetLeft;
                const y = e.clientY - rect.top + triggerZone.offsetTop;

                const text = CHAR_DIALOGUES.length > 0
                    ? CHAR_DIALOGUES[Math.floor(Math.random() * CHAR_DIALOGUES.length)]
                    : "Chạm vào Tawa để xem nhân vật đang nghĩ gì nè~ 🌸";

                const bubbleId = Date.now();
                setBubbles(prev => {
                    const newQueue = [...prev, { id: bubbleId, x: x, y: y, text: text, isFading: false }];
                    return newQueue.length > 2 ? newQueue.slice(newQueue.length - 2) : newQueue;
                });

                setTimeout(() => setBubbles(prev => prev.map(b => b.id === bubbleId ? { ...b, isFading: true } : b)), 5000);
                setTimeout(() => setBubbles(prev => prev.filter(b => b.id !== bubbleId)), 6500);
            };

            const handleImageUpload = (e) => {
                const file = e.target.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onloadend = () => {
                    const base64Result = reader.result;
                    setBgUrl(base64Result);
                    try {
                        localStorage.setItem('dsi_bg', base64Result);
                        setBgSaveStatus('saved');
                    } catch (error) {
                        setBgSaveStatus('session-only');
                        alert('Ui da! Hình ảnh bự quá Tawa lưu không nổi rồi... 💦 Nền chỉ có tác dụng tạm thời thôi nha Kẻ Dệt Mộng!');
                    }
                };
                reader.onerror = () => alert('Tawa không đọc được ảnh này rồi, thử tấm khác nha! 🌸');
                reader.readAsDataURL(file);
                e.target.value = null;
            };

            const searchRecords = parseSearchHistory(`$11`);

            const details = [
                {
                    id: 'loc', 
                    icon: <i className="fa-solid fa-map-location-dot"></i>, 
                    title: 'TỌA ĐỘ & THỜI GIAN',
                    content: (
                        <div className="info-stack">
                            <div className="detail-row">
                                <span className="detail-label">Vị trí</span>
                                <span className="detail-value" dangerouslySetInnerHTML={{__html: '$2'}}></span>
                            </div>
                            <div className="detail-row" style={{ borderBottom: 'none' }}>
                                <span className="detail-label">Giờ Hệ Thống</span>
                                <span className="detail-value text-bold" dangerouslySetInnerHTML={{__html: '$3'}}></span>
                            </div>
                            <div className="text-desc" dangerouslySetInnerHTML={{__html: '$4'}}></div>
                        </div>
                    )
                },
                {
                    id: 'outfit', 
                    icon: <i className="fa-solid fa-shirt"></i>, 
                    title: 'TRANG PHỤC HIỆN TẠI',
                    content: (
                        <div className="tag-grid">
                            <div className="tag-box">
                                <span className="detail-label mb-1">Phần trên</span>
                                <span className="detail-value" dangerouslySetInnerHTML={{__html: '$5'}}></span>
                            </div>
                            <div className="tag-box">
                                <span className="detail-label mb-1">Phần dưới</span>
                                <span className="detail-value" dangerouslySetInnerHTML={{__html: '$6'}}></span>
                            </div>
                            <div className="tag-box span-2">
                                <span className="detail-label mb-1">Trạng thái Cơ thể / Tư thế</span>
                                <span className="detail-value" dangerouslySetInnerHTML={{__html: '$7'}}></span>
                            </div>
                        </div>
                    )
                },
                {
                    id: 'mood', 
                    icon: <i className="fa-solid fa-heart-pulse"></i>, 
                    title: 'PHÂN TÍCH TÂM LÝ',
                    content: (
                        <div className="mood-box">
                            <div className="mood-circle" dangerouslySetInnerHTML={{__html: '$8'}}></div>
                            <div className="mood-info">
                                <span className="text-bold" style={{ fontSize: '0.95rem' }} dangerouslySetInnerHTML={{__html: '$9'}}></span>
                                <div className="text-desc" style={{ marginTop: '0.3rem' }} dangerouslySetInnerHTML={{__html: '$10'}}></div>
                            </div>
                        </div>
                    )
                },
                {
                    id: 'search', 
                    icon: <i className="fa-solid fa-history"></i>, 
                    title: 'BỘ NHỚ TÌM KIẾM',
                    content: (
                        <div className="search-list">
                            <div className="search-header"><span>TỪ KHÓA</span><span>THỜI GIAN</span></div>
                            {searchRecords.length > 0 ? (
                                searchRecords.map((record, idx) => (
                                    <div key={idx} className="search-item">
                                        <span className="text-ellipsis" dangerouslySetInnerHTML={{__html: record.content}}></span>
                                        <span className="text-faint" dangerouslySetInnerHTML={{__html: record.time}}></span>
                                    </div>
                                ))
                            ) : (
                                <div className="text-desc" style={{textAlign: 'center', opacity: 0.5}}>Tạm thời trống trơn nè~ 🐾</div>
                            )}
                        </div>
                    )
                },
                {
                    id: 'music', 
                    icon: <i className="fa-solid fa-headphones-simple"></i>, 
                    title: 'BẢN GHI ÂM THANH',
                    content: <MusicPlayerUI songData={songData} isLoading={isLoadingMusic} isPlaying={isPlaying} progress={progress} duration={duration} volume={volume} onTogglePlay={togglePlay} onSeek={handleSeek} onVolumeChange={handleVolume} />
                },
                {
                    id: 'settings', 
                    icon: <i className="fa-solid fa-sliders"></i>, 
                    title: 'CÀI ĐẶT DỆT MỘNG',
                    content: (
                        <div className="info-stack">
                            <div className="detail-row" style={{ borderBottom: 'none', paddingBottom: 0 }}><span className="detail-label">Định danh Hệ thống</span></div>
                            <input type="text" className="setting-input" value={charName} onChange={(e) => setCharName(e.target.value)} placeholder="Nhập tên..." />
                            <div className="detail-row" style={{ borderBottom: 'none', paddingBottom: 0, marginTop: '8px' }}><span className="detail-label">Hình nền Không gian</span></div>
                            <label className="file-upload-label">
                                <i className="fa-solid fa-cloud-arrow-up" style={{color: '#a78bfa'}}></i>
                                <span>Tải ảnh lên (GIF/PNG/JPG)</span>
                                <input type="file" accept="image/png, image/jpeg, image/gif" hidden onChange={handleImageUpload} />
                            </label>
                            <div className="text-desc" style={{textAlign:'center', fontSize: '0.75rem', color: '#a78bfa', marginTop: '6px'}}>
                                {bgSaveStatus === 'session-only' ? 'Ảnh bự quá! Chỉ lưu được lúc này thôi nha~ 💦' : 'Đã lưu an toàn vào bộ nhớ trình duyệt! ✨'}
                            </div>
                        </div>
                    )
                }
            ];

            const activeItem = details.find(d => d.id === activeId);

            return (
                <div onClick={() => !isExpanded && setIsExpanded(true)} onMouseMove={handleMouseMove} className={`swiss-island ${isExpanded ? 'expanded' : 'collapsed'}`}>
                    <audio ref={audioRef} style={{display:'none'}} />
                    <div className="island-bg-image" style={{ backgroundImage: `url(${bgUrl})`, opacity: isExpanded ? 1 : 0 }}></div>
                    <div className="island-overlay" style={{ opacity: isExpanded ? 1 : 0 }}></div>

                    {isExpanded && bubbles.map(bubble => (
                        <div key={bubble.id} className={`speech-bubble ${bubble.isFading ? 'fading' : ''}`} style={{ left: bubble.x, top: bubble.y - 20 }}>{bubble.text}</div>
                    ))}

                    <div className="capsule-content">
                        <span className="capsule-title">{charName}</span>
                        <span className="capsule-date" dangerouslySetInnerHTML={{__html: '$1'}}></span>
                    </div>

                    <div className="card-content">
                        <div className="bubble-trigger-zone" onClick={handleTriggerClick}></div>
                        <div className="card-header-row">
                            <div>
                                <h1 className="main-title">{charName}</h1>
                                <div className="status-badge"><div className="status-dot"></div><span className="status-text">ĐANG ĐỒNG BỘ TÂM TRÍ 🌸</span></div>
                            </div>
                            <button onClick={(e) => { e.stopPropagation(); setIsExpanded(false); setActiveId(null); setBubbles([]); }} className="close-btn">
                                <i className="fa-solid fa-xmark"></i>
                            </button>
                        </div>

                        <div className="content-display-area" onClick={(e) => e.stopPropagation()}>
                            {activeItem && (
                                <div className="detail-glass-box" key={activeItem.id}>
                                    <div className="detail-header-title">{activeItem.title}</div>
                                    {activeItem.content}
                                </div>
                            )}
                        </div>

                        <div className="nav-footer" onClick={(e) => e.stopPropagation()}>
                            {details.map((item) => (
                                <button key={item.id} className={`nav-icon-btn ${activeId === item.id ? 'active' : ''}`} onClick={(e) => { e.stopPropagation(); setActiveId(activeId === item.id ? null : item.id); }}>
                                    <span>{item.icon}</span>
                                    <div className="nav-dot"></div>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            );
        };

        const root = ReactDOM.createRoot(document.getElementById('root'));
        root.render(<SwissDynamicIsland />);
    </script>
</body>
</html>
