<!DOCTYPE html>
<html lang="vi-VN">
<head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>Bộ chọn nhánh Dệt Mộng</title>
    <!-- Đồng bộ Font chữ với hệ sinh thái Tawa -->
    <link href="https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800&family=Georgia&display=swap" rel="stylesheet">
    <style>
        :root {
            --font-main: 'Nunito', system-ui, -apple-system, sans-serif;
            --font-serif: 'Georgia', serif;
        }

        body {
            margin: 0; padding: 0; max-width: 100%; overflow-x: hidden; background: transparent !important;
        }

        /* Ẩn các phần không cần thiết của SillyTavern và khu vực tham số cấu hình */
        .branch-selector .mermaid, .branch-selector .mermaid * { display: none !important; }
        #raw-options-data, #raw-options-data a { display: none !important; }

        /* --- Thành phần cơ bản cốt lõi --- */
        .branch-selector { position: relative; max-width: 100%; transition: all 0.4s ease; box-sizing: border-box; font-family: var(--font-main); }
        .collapsible-container { width: 100%; position: relative; z-index: 2; }

        .summary-text { cursor: pointer; display: flex; align-items: center; transition: all 0.3s ease; user-select: none; outline: none; }
        .summary-text::-webkit-details-marker { display: none; }

        #options-container { padding: 0; margin: 0; display: flex; flex-direction: column; list-style: none; }

        .clickable-text { cursor: pointer; transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1); position: relative; }
        .clickable-text li { list-style: none; pointer-events: none; margin: 0; padding: 0; }

        /* ==================== KIỂU V2 (TAWA GỐC - DREAMWEAVER) ==================== */
        .theme-light .style-v2 {
            --v2-text: #2d3748; --v2-accent: #ff7eb3;
            --v2-bg: rgba(255, 255, 255, 0.7); --v2-border: rgba(255, 126, 179, 0.3);
            --v2-butterfly: rgba(255, 126, 179, 0.4); --v2-blend: multiply;
        }

        .theme-dark .style-v2 {
            --v2-text: #e2e8f0; --v2-accent: #ff7eb3;
            --v2-bg: rgba(20, 16, 40, 0.6); --v2-border: rgba(255, 126, 179, 0.2);
            --v2-butterfly: rgba(255, 126, 179, 0.5); --v2-blend: screen;
        }

        .style-v2 {
            margin: 12px 0; padding: 15px; border-radius: 16px;
            background: var(--v2-bg); border: 1px solid var(--v2-border);
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
            backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
            color: var(--v2-text);
        }

        /* Hiệu ứng bướm bay lượn */
        @keyframes float-butterfly {
            0%, 100% { transform: translateY(0) rotate(15deg); }
            50% { transform: translateY(-8px) rotate(10deg); }
        }
        @keyframes float-butterfly-alt {
            0%, 100% { transform: translateY(0) rotate(-10deg) scaleX(-1); }
