                if (events.length === 1) {
                    const ev = events[0];
                    const dateLabel = `${ev.dateStr}${ev.dayName ? ` ${ev.dayName}` : ''}`.trim();
                    const npcLabel = ev.npcAction && ev.npcAction.trim() !== '' ? `\n[Tài liệu ẩn: Động thái NPC trong bóng tối: ${ev.npcAction}]` : '';
                    return `[Chỉ thị Tối cao]: Hãy đẩy dòng thời gian đến [${ev.time}, ${dateLabel}], tại [${ev.location}]. Khởi chạy sự kiện: "${ev.title}".\nNội dung trọng tâm: ${ev.description}${npcLabel}`;
                }
                return `[Chỉ thị Tối cao]: Hãy đẩy dòng thời gian cốt truyện để chạy liên tiếp chuỗi sự kiện sau đây một cách logic và tự nhiên nhất:\n\n${events.map((ev, index) => formatEventPrompt(ev)).join('\n\n')}`;
            }

            function getSelectedEvents() { return Array.from(selectedEventIds).map(id => eventLookup.get(id)).filter(Boolean).sort((a, b) => a.dayIndex - b.dayIndex || a.eventIndex - b.eventIndex); }
            function updateSelectionUI() {
                const count = selectedEventIds.size;
                if (selectionCount) selectionCount.textContent = String(count);
                if (composeBtn) { composeBtn.disabled = count === 0; }
                if (clearSelectionBtn) clearSelectionBtn.disabled = count === 0;
            }

            async function fallbackSetInput(text) {
                try {
                    const hostWindow = window.parent && window.parent !== window ? window.parent : window;
                    const hostDocument = hostWindow.document;
                    const selectors = ['#send_textarea', 'textarea#send_textarea', 'textarea[name=\"user_input\"]', '#chat-input textarea', 'textarea'];
                    let inputEl = null;

                    selectors.some(selector => {
                        const found = Array.from(hostDocument.querySelectorAll(selector)).find(node => !node.disabled && !node.readOnly && (node.offsetParent !== null || selector === 'textarea'));
                        if (found) { inputEl = found; return true; } return false;
                    });
                    if (!inputEl) return false;

                    inputEl.focus();
                    if (inputEl.tagName === 'TEXTAREA' || inputEl.tagName === 'INPUT') {
                        const proto = inputEl.tagName === 'TEXTAREA' ? hostWindow.HTMLTextAreaElement.prototype : hostWindow.HTMLInputElement.prototype;
                        const descriptor = Object.getOwnPropertyDescriptor(proto, 'value');
                        if (descriptor && descriptor.set) descriptor.set.call(inputEl, text); else inputEl.value = text;
                    } else if (inputEl.isContentEditable) { inputEl.textContent = text; }

                    inputEl.dispatchEvent(new hostWindow.Event('input', { bubbles: true }));
                    inputEl.dispatchEvent(new hostWindow.Event('change', { bubbles: true }));
                    return true;
                } catch (error) { return false; }
            }

            async function writeToUserInput(text, title, count = 1) {
