        const parseSearchHistory = (xmlString) => {
            if (!xmlString || xmlString.startsWith('$')) return [];
            const recordRegex = /<Lịch sử tìm kiếm>(.*?)<\/Lịch sử tìm kiếm>/gs;
            const records = [];
            let recordMatch;
            while ((recordMatch = recordRegex.exec(xmlString)) !== null) {
                const recordContent = recordMatch[1];
                const contentMatch = /<Nội dung>(.*?)<\/Nội dung>/.exec(recordContent);
                const timeMatch = /<Thời gian>(.*?)<\/Thời gian>/.exec(recordContent);
                if (contentMatch && timeMatch) {
                    records.push({
                        content: contentMatch[1].trim(),
                        time: timeMatch[1].trim()
                    });
                }
            }
            return records;
