                    <button class="color-preset-btn" style="--preset-color: #a78bfa;" title="Tím Ngân Hà" onclick="setPresetColor(this, '#a78bfa')"></button>
                    <button class="color-preset-btn" style="--preset-color: #38bdf8;" title="Xanh Lưu Ly" onclick="setPresetColor(this, '#38bdf8')"></button>

