    <script>
        (function () {
            const currentScript = document.currentScript;
            const container = currentScript.closest('.novel-header-container');
            const btn = container.querySelector('.theme-toggle-btn');
            const icon = btn.querySelector('.toggle-icon');

            const sunSvg = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"></line><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"></line><line x1="1" y1="12" x2="3" y2="12"></line><line x1="21" y1="12" x2="23" y2="12"></line><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"></line><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"></line></svg>';
            const moonSvg = '<svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path></svg>';

            const savedPref = localStorage.getItem('novel_theme_preference_v2');
            if (savedPref === 'night') {
                container.classList.add('night-mode');
                icon.innerHTML = moonSvg;
            } else {
                icon.innerHTML = sunSvg;
            }

            btn.onclick = function() {
                container.classList.toggle('night-mode');
                const isNight = container.classList.contains('night-mode');
                icon.innerHTML = isNight ? moonSvg : sunSvg;
                localStorage.setItem('novel_theme_preference_v2', isNight ? 'night' : 'day');
            };

            const dropdown = container.querySelector('#color-dropdown');
            const colorPicker = container.querySelector('.night-color-picker-input');

            window.toggleColorPanel = function(e) {
                e.stopPropagation();
                dropdown.classList.toggle('active');
            };

            document.addEventListener('click', function(e) {
                if (dropdown && !dropdown.contains(e.target)) dropdown.classList.remove('active');
            });

            function hexToRgb(hex) {
                const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
                return result ? { r: parseInt(result[1], 16), g: parseInt(result[2], 16), b: parseInt(result[3], 16) } : null;
            }

            function updateNightColor(hexColor, syncAll = true) {
                const rgb = hexToRgb(hexColor);
                if (rgb) {
                    if (syncAll) {
                        document.querySelectorAll('.novel-header-container').forEach(cont => {
                            cont.style.setProperty('--night-accent-hex', hexColor);
                            cont.style.setProperty('--night-r', rgb.r);
                            cont.style.setProperty('--night-g', rgb.g);
                            cont.style.setProperty('--night-b', rgb.b);
                            const picker = cont.querySelector('.night-color-picker-input');
                            if (picker && picker !== colorPicker) picker.value = hexColor;
                        });
                    } else {
                        container.style.setProperty('--night-accent-hex', hexColor);
                        container.style.setProperty('--night-r', rgb.r);
                        container.style.setProperty('--night-g', rgb.g);
                        container.style.setProperty('--night-b', rgb.b);
                    }
                }
            }

            const savedColor = localStorage.getItem('novel_theme_color_v2');
            if (savedColor) {
                colorPicker.value = savedColor;
                updateNightColor(savedColor, false);
            }

            colorPicker.addEventListener('input', function(e) { updateNightColor(e.target.value, true); });
            colorPicker.addEventListener('change', function(e) { localStorage.setItem('novel_theme_color_v2', e.target.value); });

            window.setPresetColor = function(btnElement, hexColor) {
                const parentCont = btnElement.closest('.novel-header-container');
                if (parentCont) {
                    const picker = parentCont.querySelector('.night-color-picker-input');
                    if (picker) {
                        picker.value = hexColor;
                        const rgb = hexToRgb(hexColor);
                        if (rgb) {
                             document.querySelectorAll('.novel-header-container').forEach(cont => {
                                cont.style.setProperty('--night-accent-hex', hexColor);
                                cont.style.setProperty('--night-r', rgb.r);
                                cont.style.setProperty('--night-g', rgb.g);
                                cont.style.setProperty('--night-b', rgb.b);
                                const contPicker = cont.querySelector('.night-color-picker-input');
                                if (contPicker) contPicker.value = hexColor;
                            });
                        }
                        localStorage.setItem('novel_theme_color_v2', hexColor);
                    }
                }
            };

            const metaContainer = container.querySelector('#novel-meta-container');
            const cpRaw = metaContainer.getAttribute('data-cp') || '';
            const locRaw = metaContainer.getAttribute('data-loc') || '';
            const cpGroups = cpRaw.split(/[,，]/).map(g => g.trim()).filter(g => g);

            function parseCPGroup(group) {
                const parts = group.split(/\s*([×xX&])\s*/);
                let html = '';
                parts.forEach((part, idx) => {
                    if (!part.trim()) return;
                    if (idx % 2 === 1) html += `<span class="novel-cp-relation">${part.trim()}</span>`;
                    else html += `<span class="novel-cp-name">${part.trim()}</span>`;
                });
                return html;
            }

            let contentHTML = '';

            if (cpGroups.length > 0) {
                const cpHTML = cpGroups.map(g => `<div class="novel-cp-group">${parseCPGroup(g)}</div>`).join('<span style="opacity:0.3; margin:0 5px">/</span>');
                contentHTML += `<div class="novel-meta-row"><div class="novel-meta-item"><span class="novel-meta-label">Couple</span>${cpHTML}</div></div>`;
            }

            if (locRaw) {
                contentHTML += `<div class="novel-meta-row"><div class="novel-meta-item"><span class="novel-meta-label">Location</span><span>${locRaw}</span></div></div>`;
            }

            metaContainer.innerHTML = contentHTML;

            const tagsContainer = container.querySelector('#novel-tags-container');
            if (tagsContainer) {
                const tagsRaw = tagsContainer.getAttribute('data-tags') || '';
                // Sửa lỗi: Cố tình không hiển thị thẻ span nếu tag trống (Fix khoảng trống dư thừa khi dùng thẻ div)
                if (tagsRaw.trim() === '') {
                    tagsContainer.style.display = 'none';
                } else {
                    const tags = tagsRaw.split(/[\/，,]/).map(t => t.trim()).filter(t => t);
                    tagsContainer.innerHTML = '';
                    tags.forEach(tag => {
                        const span = document.createElement('span');
                        span.className = 'novel-tag';
                        span.textContent = tag;
                        tagsContainer.appendChild(span);
                    });
                }
            }
        })();
    </script>
</div>
</body>
</html>
