    <script>
        (function () {
            const rawDataContainer = document.getElementById('calendar-raw-data-v4'); if (!rawDataContainer) return; const rawString = rawDataContainer.textContent.trim();
            const lines = rawString.split(/\r?\n/); const calendarData = []; let currentDayObj = null;
            lines.forEach(line => {
                line = line.trim(); if (!line) return;
                if (line.startsWith('Date:')) {
                    const parts = line.replace('Date:', '').split('|').map(s => s.trim()); if (parts.length >= 1) { currentDayObj = { dateStr: parts[0], dayName: parts[1] || '', events: [] }; calendarData.push(currentDayObj); }
                } else if (line.startsWith('Event:') && currentDayObj) {
                    const parts = line.replace('Event:', '').split('|').map(s => s.trim());
                    if (parts.length >= 5) {
                        currentDayObj.events.push({
                            type: parts[0], title: parts[1], description: parts[2], time: parts[3], location: parts[4], npcAction: parts[5] || ''
                        });
                    }
                }
            });

            const scroller = document.getElementById('app-scroller-v4');
            const eventList = document.getElementById('app-list-v4');
            const footerStatus = document.getElementById('appFooterStatusV4');
            const selectionCount = document.getElementById('appSelectionCountV4');
            const selectionHint = document.getElementById('appSelectionHintV4');
            const composeBtn = document.getElementById('appComposeBtnV4');
            const clearSelectionBtn = document.getElementById('appClearSelectionBtnV4');
            const selectedEventIds = new Set();
            const eventLookup = new Map();
            let activeDayData = null;

            function getTypeColor(type) { if (type === 'world') return 'var(--accent-world)'; if (type === 'major') return 'var(--accent-major)'; if (type === 'user') return 'var(--accent-user)'; if (type === 'character') return 'var(--accent-char)'; return '#ccc'; }
            function translateType(type) { if (type === 'world') return 'Thế giới'; if (type === 'major') return 'Sự kiện lớn'; if (type === 'user') return 'Cá nhân'; if (type === 'character') return 'Ràng buộc NPC'; return 'Khác'; }
            function setStatus(text, isError = false) { if (!footerStatus) return; footerStatus.textContent = text; footerStatus.style.color = isError ? '#f87171' : 'var(--accent-char)'; }

            function formatEventPrompt(ev) {
                const dateLabel = `${ev.dateStr}${ev.dayName ? ` ${ev.dayName}` : ''}`.trim();
                const npcLabel = ev.npcAction && ev.npcAction.trim() !== '' ? `\n> Động thái NPC lúc này: ${ev.npcAction}` : '';
                return `- Vào lúc [${ev.time}, ${dateLabel}] tại [${ev.location}]: Tiến hành sự kiện ${translateType(ev.type)} mang tên "${ev.title}".\n> Nội dung chính: ${ev.description}${npcLabel}`;
            }
            function buildInputText(events) {
                if (!events || events.length === 0) return '';
                if (events.length === 1) {
                    const ev = events[0];
                    const dateLabel = `${ev.dateStr}${ev.dayName ? ` ${ev.dayName}` : ''}`.trim();
                    const npcLabel = ev.npcAction && ev.npcAction.trim() !== '' ? `\n[Tài liệu ẩn: Động thái NPC trong bóng tối: ${ev.npcAction}]` : '';
                    return `[Chỉ thị Tối cao]: Hãy đẩy dòng thời gian đến [${ev.time}, ${dateLabel}], tại [${ev.location}]. Khởi chạy sự kiện: "${ev.title}".\nNội dung trọng tâm: ${ev.description}${npcLabel}`;
                }
                return `[Chỉ thị Tối cao]: Hãy đẩy dòng thời gian cốt truyện để chạy liên tiếp chuỗi sự kiện sau đây một cách logic và tự nhiên nhất:\n\n${events.map((ev, index) => formatEventPrompt(ev)).join('\n\n')}`;
            }

            function getSelectedEvents() { return Array.from(selectedEventIds).map(id => eventLookup.get(id)).filter(Boolean).sort((a, b) => a.dayIndex - b.dayIndex || a.eventIndex - b.eventIndex); }
            function updateSelectionUI() {
                const count = selectedEventIds.size;
                if (selectionCount) selectionCount.textContent = String(count);
                if (composeBtn) { composeBtn.disabled = count === 0; }
                if (clearSelectionBtn) clearSelectionBtn.disabled = count === 0;
            }

            async function fallbackSetInput(text) {
                try {
                    const hostWindow = window.parent && window.parent !== window ? window.parent : window;
                    const hostDocument = hostWindow.document;
                    const selectors = ['#send_textarea', 'textarea#send_textarea', 'textarea[name=\"user_input\"]', '#chat-input textarea', 'textarea'];
                    let inputEl = null;

                    selectors.some(selector => {
                        const found = Array.from(hostDocument.querySelectorAll(selector)).find(node => !node.disabled && !node.readOnly && (node.offsetParent !== null || selector === 'textarea'));
                        if (found) { inputEl = found; return true; } return false;
                    });
                    if (!inputEl) return false;

                    inputEl.focus();
                    if (inputEl.tagName === 'TEXTAREA' || inputEl.tagName === 'INPUT') {
                        const proto = inputEl.tagName === 'TEXTAREA' ? hostWindow.HTMLTextAreaElement.prototype : hostWindow.HTMLInputElement.prototype;
                        const descriptor = Object.getOwnPropertyDescriptor(proto, 'value');
                        if (descriptor && descriptor.set) descriptor.set.call(inputEl, text); else inputEl.value = text;
                    } else if (inputEl.isContentEditable) { inputEl.textContent = text; }

                    inputEl.dispatchEvent(new hostWindow.Event('input', { bubbles: true }));
                    inputEl.dispatchEvent(new hostWindow.Event('change', { bubbles: true }));
                    return true;
                } catch (error) { return false; }
            }

            async function writeToUserInput(text, title, count = 1) {
                try {
                    if (typeof triggerSlash === 'function') {
                        await triggerSlash('/setinput ' + text);
                        setStatus(count > 1 ? `Đã nạp ${count} sự kiện vào khung chat thành công! Nhấn Enter để gửi nha~ 🌸` : `Đã nạp sự kiện "${title}" vào khung chat! ✨`);
                        return;
                    }
                } catch (error) {}
                const ok = await fallbackSetInput(text);
                if (ok) setStatus(count > 1 ? `Đã nạp ${count} sự kiện vào khung chat thành công! Nhấn Enter để gửi nha~ 🌸` : `Đã nạp sự kiện "${title}" vào khung chat! ✨`);
                else setStatus('Tawa không tìm thấy khung chat để nhập lệnh òi... 💦', true);
            }

            function render() {
                scroller.innerHTML = '';
                if (calendarData.length > 0) { renderScroller(0); renderEvents(calendarData[0]); }
                else { eventList.innerHTML = '<div class="empty-state">Lịch trình trống trơn nè~ 🐾</div>'; }
            }

            function renderScroller(activeIndex) {
                calendarData.forEach((day, index) => {
                    const card = document.createElement('div');
                    card.className = `date-card ${index === activeIndex ? 'active' : ''}`;

                    // Format DD/MM (vd: 15/8) => parts[0]=ngày, parts[1]=tháng
                    const dateParts = day.dateStr.trim().split(/[\/\-]/);
                    const dayNum   = dateParts[0];
                    const monthNum = dateParts[1] || '';

                    let dotsHtml = '';
                    day.events.forEach(ev => {
                        let color = getTypeColor(ev.type);
                        dotsHtml += `<div class="dot" style="background-color: ${color}"></div>`;
                    });

                    card.innerHTML = `
                        <span class="day-name">${day.dayName}</span>
                        <span class="day-num">${dayNum}</span>
                        <span class="day-month">/${monthNum}</span>
                        <div class="event-dots">${dotsHtml}</div>
                    `;

                    card.onclick = () => {
                        const allCards = scroller.querySelectorAll('.date-card');
                        allCards.forEach(c => c.classList.remove('active'));
                        card.classList.add('active');
                        renderEvents(day);
                    };
                    scroller.appendChild(card);
                });
            }

            function renderEvents(dayData) {
                activeDayData = dayData; eventList.innerHTML = '';
                if (!dayData || dayData.events.length === 0) { eventList.innerHTML = '<div class="empty-state">Hôm nay không có lịch trình gì hết á! Nghỉ ngơi thui~ 💤</div>'; return; }
                dayData.events.forEach(ev => {
                    const details = document.createElement('details'); details.className = `event-details-card type-${ev.type}`;
                    details.classList.toggle('selected', selectedEventIds.has(ev.id));
                    let icon = '📍'; if (ev.type === 'world') icon = '🌍'; if (ev.type === 'major') icon = '🎉'; if (ev.type === 'user') icon = '🌸'; if (ev.type === 'character') icon = '💕';
                    const isSelected = selectedEventIds.has(ev.id);

                    let descriptionWrapperHtml = '';
                    const hasDesc = ev.description && ev.description.trim() !== ''; const hasNpcAction = ev.npcAction && ev.npcAction.trim() !== '';
                    if (hasDesc || hasNpcAction) {
                        let innerHtml = '';
                        if (hasDesc) innerHtml += `<div class="event-description">${ev.description}</div>`;
                        if (hasNpcAction) innerHtml += `<div class="event-npc-note" ${hasDesc ? 'style="margin-top: 12px;"' : ''}>${ev.npcAction}</div>`;
                        descriptionWrapperHtml = `<div class="event-description-wrapper">${innerHtml}</div>`;
                    }

                    details.innerHTML = `
                        <summary class="event-summary">
                            <div class="arrow-icon">›</div>
                            <div class="event-meta-row">
                                <span class="event-meta-left"><span>${ev.time}</span><span>${translateType(ev.type)}</span></span>
                                <button class="event-select-btn ${isSelected ? 'selected' : ''}" type="button" aria-pressed="${isSelected ? 'true' : 'false'}">${isSelected ? 'Đã chọn 🦋' : 'Chọn 🦋'}</button>
                            </div>
                            <div class="event-title">${ev.title}</div>
                            <div class="event-loc">${icon} ${ev.location}</div>
                        </summary>
                        ${descriptionWrapperHtml}
                    `;
                    const selectBtn = details.querySelector('.event-select-btn');
                    selectBtn.addEventListener('click', event => {
                        event.preventDefault(); event.stopPropagation();
                        if (selectedEventIds.has(ev.id)) selectedEventIds.delete(ev.id); else selectedEventIds.add(ev.id);
                        details.classList.toggle('selected', selectedEventIds.has(ev.id));
                        selectBtn.classList.toggle('selected', selectedEventIds.has(ev.id));
                        selectBtn.setAttribute('aria-pressed', selectedEventIds.has(ev.id) ? 'true' : 'false');
                        selectBtn.textContent = selectedEventIds.has(ev.id) ? 'Đã chọn 🦋' : 'Chọn 🦋';
                        updateSelectionUI();
                    });
                    eventList.appendChild(details);
                });
            }

            if (composeBtn) {
                composeBtn.addEventListener('click', () => {
                    const selectedEvents = getSelectedEvents(); if (selectedEvents.length === 0) return;
                    const leadTitle = selectedEvents.length === 1 ? selectedEvents[0].title : `${selectedEvents.length} lịch trình`;
                    writeToUserInput(buildInputText(selectedEvents), leadTitle, selectedEvents.length);
                });
            }
            if (clearSelectionBtn) {
                clearSelectionBtn.addEventListener('click', () => {
                    selectedEventIds.clear(); updateSelectionUI(); if (activeDayData) renderEvents(activeDayData);
                    setStatus('Tawa đã quét dọn sạch sẽ các mục đã chọn gòi nè! ✨');
