          const eyedropper = new Eye();
          eyedropper
            .open()
            .then((res) => {
              const { r, g, b } = hexToRgb(res.sRGBHex);
              settings.ballColor = { ...settings.ballColor, r, g, b };
              hsv = rgbToHsv(r, g, b);
              drawSV();
              drawHue();
              drawAlpha();
              updateFieldsFromColor();
              applyBallAppearance();
              applyThemeFromBallColor();
              saveSettings();
            })
            .catch(() => {});
