      } else {
        ball.style.left = settings.ballPosition.left;
        ball.style.top = settings.ballPosition.top;
        ball.style.right = "auto";
        ball.style.bottom = "auto";
      }

      isInitialized = true;
      log("Khởi tạo hoàn tất.");
    }

    // Mở bảng chính
    function openPanel() {
      if (!isInitialized) masterInitialize();
      setTimeout(() => {
        allPresetsCache = null;
        populateMainMenu();
        const $p = window.parent.$(`#${PANEL_ID}`);
        $p.find(".theme-toggle").attr("data-mode", settings.themeMode);
        window.parent.$(`.${MAIN_OVERLAY_CLS}`).css("display", "flex");
        lockScroll(window.parent.document);
        window.parent
          .$("#preset-tagger-show-ball")
          .prop("checked", settings.showBall);
        fitMainPanel();
        alignVisibleOverlays();
      }, 50);
    }

    // Điểm đầu vào
    function start() {
      loadSettings();

      // Dọn dẹp tất cả tài nguyên khi script bị gỡ bỏ
      $(window).on("pagehide", () => {
        const parent$ = window.parent.$;
        const parentDoc = window.parent.document;

        // Dọn dẹp phần tử DOM
        parent$(`#${BUTTON_ID}`).remove();
        parent$(`.${MAIN_OVERLAY_CLS}`).remove();
        parent$(`.${QUICK_OVERLAY_CLS}`).remove();
        parent$(`.${CUSTOMIZE_OVERLAY_CLS}`).remove();
        parent$(`#${FLOATING_BALL_ID}`).remove();
        parent$(`#${STYLE_ID}`).remove();
        parent$(`#${THEME_STYLE_ID}`).remove();

        // Dọn dẹp sự kiện lắng nghe
        parent$("body").off(".tagger");
        parent$(parentDoc).off(".tagger");

        // Đặt lại trạng thái
        isInitialized = false;
        allPresetsCache = null;

        // Dọn dẹp kiểu khắc phục zoom trên iOS
        try {
          const zoomFix = parentDoc.getElementById("pt-ios-zoom-fix");
          if (zoomFix) zoomFix.remove();
        } catch (_) {}

        log("Script đã được gỡ bỏ, tài nguyên đã được dọn dẹp.");
      });

      const createButtonInterval = setInterval(() => {
        const parent$ = window.parent.$;
        if (
          parent$ &&
          parent$(`#extensionsMenu`).length > 0 &&
          window.parent.TavernHelper
        ) {
          clearInterval(createButtonInterval);
          if (parent$(`#${BUTTON_ID}`).length === 0) {
            const $btn = parent$("<div/>", {
              id: BUTTON_ID,
              class: "list-group-item flex-container flexGap5 interactable",
            });
            $btn.append('<i class="fa-solid fa-tags"></i>');
            $btn.append(parent$("<span/>").text("Thẻ nhanh Preset"));
            $btn.on("click", (ev) => {
              ev.stopPropagation();
              window.parent.$("body").trigger("click");
              openPanel();
            });
            $btn.appendTo(parent$(`#extensionsMenu`));
            log("Nút đã được tạo. Đang chờ tương tác.");

            if (settings.showBall) {
              const readyInterval = setInterval(() => {
                if (window.parent.document.readyState === "complete") {
                  clearInterval(readyInterval);
                  if (!isInitialized) masterInitialize();
                  setTimeout(() => {
                    applyBallAppearance();
                    window.parent
                      .$(`#${FLOATING_BALL_ID}`)
                      .css("display", "flex");
                  }, 100);
                }
              }, 200);
            }
          }
        }
      }, 200);
    }
    start();
  })(),
);

const config = {
    moduleUrl: 'https://cdn.jsdelivr.net/npm/mermaid@11.12.3/+esm'
};

const {
    eventSource,
    event_types,
} = SillyTavern.getContext();

const events = [
    event_types.CHARACTER_MESSAGE_RENDERED,
    event_types.USER_MESSAGE_RENDERED,
    event_types.CHAT_CHANGED,
    event_types.MESSAGE_SWIPED,
    event_types.MESSAGE_UPDATED,
];

// --- Chế độ tối + Điểm xuyết bằng biến của SillyTavern ---
function applyDynamicMermaidTheme(mainWindow, mainDoc) {
    try {
        const bodyStyle = window.getComputedStyle(mainDoc.body);

        const emColor = bodyStyle.getPropertyValue('--SmartThemeEmColor').trim() || '#888888';
        const underlineColor = bodyStyle.getPropertyValue('--SmartThemeUnderlineColor').trim() || '#888888';
        const userMesBlurTintColor = bodyStyle.getPropertyValue('--SmartThemeUserMesBlurTintColor').trim() || '#222222';
        const mainFontFamily = bodyStyle.getPropertyValue('--mainFontFamily') || 'inherit';

        mainWindow.mermaid.initialize({
            themeVariables: {
                // Văn bản và đường kẻ
                textColor: emColor,
                primaryTextColor: emColor,
                lineColor: underlineColor,
                // Nền của node (nút)
                primaryColor: userMesBlurTintColor,  // Node thông thường
                tertiaryColor: userMesBlurTintColor, // Node đặc biệt
                edgeLabelBackground: 'transparent',
            },
            fontFamily: mainFontFamily,
            theme: 'dark',
        });
    } catch (e) {
        console.warn('Áp dụng chủ đề động Mermaid thất bại', e);
    }
}

async function renderMermaidCharts() {
    const mainWindow = window.parent;
    if (!mainWindow || !mainWindow.document || typeof mainWindow.mermaid === 'undefined') return;

    const mainDoc = mainWindow.document;
    const chatElement = mainDoc.getElementById('chat');
    if (!chatElement) return;

    // Áp dụng chủ đề trước khi kết xuất (render)
    applyDynamicMermaidTheme(mainWindow, mainDoc);

    const blocks = Array.from(mainDoc.querySelectorAll('#chat pre code:not([data-processed="true"])'));
    const nodesToRender = [];

    for (const block of blocks) {
        if (block.classList.contains('custom-language-mermaid') || block.classList.contains('language-mermaid')) {
            const $codeBlock = $(block);
            const $preBlock = $codeBlock.parent('pre');

            let rawText = block.innerText || $codeBlock.text();
            let graphDefinition = rawText.replace(/\u00A0/g, ' ').trim();

            // Làm sạch bằng Regex
            graphDefinition = graphDefinition.replace(/(?<=\s)\((.*?)\)/g, '（$1）');
            graphDefinition = graphDefinition.replace(/(?<=\s)\[(.*?)\]/g, '【$1】');
            graphDefinition = graphDefinition.replace(/(?<=\s)\{(.*?)\}/g, '【$1】');

            if (!graphDefinition) continue;

            try {
                await mainWindow.mermaid.parse(graphDefinition);
                $preBlock.addClass('mermaid').text(graphDefinition);
                $preBlock.prev('.mermaid-error-warning').remove();
                nodesToRender.push($preBlock[0]);
            } catch (error) {
                console.warn('Lỗi cú pháp Mermaid:', error);
                if ($preBlock.prev('.mermaid-error-warning').length === 0) {
                    $preBlock.before('<div class="mermaid-error-warning" style="color: #c71919; font-size: 14px;">⚠️ Kết xuất biểu đồ Mermaid thất bại, vui lòng kiểm tra lại lỗi cú pháp.</div>');
                }
            } finally {
                block.setAttribute('data-processed', 'true');
            }
        }
    }

    if (nodesToRender.length > 0) {
        const chatHeight = chatElement.scrollHeight;
        const scrollPosition = chatElement.scrollTop;

        try {
            await mainWindow.mermaid.run({
                nodes: nodesToRender,
                suppressErrors: true
            });
        } catch (e) {
            console.error('Lỗi khi chạy Mermaid Run:', e);
        }

        const newChatHeight = chatElement.scrollHeight;
        const diff = newChatHeight - chatHeight;
        if (Math.abs(diff) > 1) {
            chatElement.scrollTop = scrollPosition + diff;
        }
    }
}

jQuery(() => {
    const mainWindow = window.parent;
    if (!mainWindow || !mainWindow.document) return;
    const mainDoc = mainWindow.document;

    // Tiêm CSS
    if (!mainDoc.getElementById('mermaid-custom-style')) {
        const styleEl = mainDoc.createElement('style');
        styleEl.id = 'mermaid-custom-style';
        styleEl.textContent = `
            .mermaid>svg {
                display: block;
                background: rgba(0, 0, 0, 0.4);
                padding: 15px;
                margin: 0 auto;
                border: 1px var(--SmartThemeBorderColor) solid;
                border-radius: 8px;
            }
        `;
        const firstStyle = mainDoc.querySelector('style');
        if (firstStyle) firstStyle.after(styleEl);
        else mainDoc.head.appendChild(styleEl);
    }

    // Khởi tạo
    if (typeof mainWindow.mermaid === 'undefined') {
        const script = mainDoc.createElement('script');
        script.type = 'module';
        script.textContent = `
            import mermaid from '${config.moduleUrl}';
            window.mermaid = mermaid;
            window.mermaid.initialize({
                startOnLoad: false,
                securityLevel: 'loose',
            });
            window.dispatchEvent(new Event('mermaid_ready'));
        `;
        mainDoc.head.appendChild(script);

        mainWindow.addEventListener('mermaid_ready', () => {
            for (const event of events) {
                eventSource.on(event, renderMermaidCharts);
            }
            renderMermaidCharts();
        }, { once: true });
    } else {
        for (const event of events) {
            eventSource.on(event, renderMermaidCharts);
        }
        renderMermaidCharts();
    }
});

