    // 智能LRU淘汰机制
    function trimObjectKeys(obj, maxKeys = 15) {
        const keys = Object.keys(obj);
        if (keys.length > maxKeys) {
            const toRemove = keys.slice(0, keys.length - maxKeys);
            toRemove.forEach(k => delete obj[k]);
        }
    }

    function loadState() {
        try {
            state.url = localStorage.getItem(STORAGE_KEYS.url) || '';
            state.key = localStorage.getItem(STORAGE_KEYS.key) || '';
            state.model = localStorage.getItem(STORAGE_KEYS.model) || '';
            let bx = localStorage.getItem(STORAGE_KEYS.ballX);
            let by = localStorage.getItem(STORAGE_KEYS.ballY);
            state.ballX = bx !== null ? parseInt(bx) : null;
            state.ballY = by !== null ? parseInt(by) : null;

            const savedData = localStorage.getItem(STORAGE_KEYS.data);
            if (savedData) state.schedules = JSON.parse(savedData) || {};

            const savedTheaterData = localStorage.getItem(STORAGE_KEYS.theaterData);
            if (savedTheaterData) state.theater = JSON.parse(savedTheaterData) || {};

            const savedModels = localStorage.getItem(STORAGE_KEYS.models);
            if (savedModels) state.availableModels = JSON.parse(savedModels) || [];

            let savedSys = localStorage.getItem(STORAGE_KEYS.sysPrompt);
            let savedUser = localStorage.getItem(STORAGE_KEYS.userPrompt);

            if (savedSys && !savedSys.includes('Tawa bình luận')) {
                savedSys = DEFAULT_SYS_PROMPT;
            }
            if (savedUser && !savedUser.includes('xiaoday_comment')) {
                savedUser = DEFAULT_USER_PROMPT;
            }
            state.sysPrompt = savedSys || DEFAULT_SYS_PROMPT;
            state.userPrompt = savedUser || DEFAULT_USER_PROMPT;

            state.theaterPrompt = localStorage.getItem(STORAGE_KEYS.theaterPrompt) || state.theaterPrompt;

            const savedThPresets = localStorage.getItem(STORAGE_KEYS.theaterPresets);
            if (savedThPresets) {
                state.theaterPresets = JSON.parse(savedThPresets);
            } else {
                state.theaterPresets = [{
                    id: 'default', 
                    name: 'Văn phong lãng mạn', 
                    prompt: '【Hồ Sơ Cốt Truyện Gần Đây】:\n{{context}}\n\nHãy dùng văn phong lãng mạn, điện ảnh để dệt nên một Góc Kịch Nhỏ (Tiểu kịch trường) cho cốt truyện này. Hỗ trợ dùng thẻ HTML (<b>, <i>, <span style="color:pink">) để trang trí. Trả về nội dung đã Render, KHÔNG bọc trong Code Block Markdown.'
                }];
            }
            state.currentTheaterPresetId = localStorage.getItem('sgn_v26_curr_th_preset') || 'default';

            const currentThP = state.theaterPresets.find(p => p.id === state.currentTheaterPresetId);
            if (currentThP) state.theaterPrompt = currentThP.prompt;

            const savedFav = localStorage.getItem(STORAGE_KEYS.favTheaters);
            if (savedFav) state.favoriteTheaters = JSON.parse(savedFav) || [];

            const logData = localStorage.getItem(STORAGE_KEYS.apiLog);
            if (logData) {
                const parsedLog = JSON.parse(logData);
                if (parsedLog.status !== undefined && !parsedLog.schedule) {
                    state.apiLog = {
                        schedule: parsedLog,
                        theater: { status: 'none', time: '', duration: '', req: '', res: '', error: '' }
                    };
                } else {
                    state.apiLog = parsedLog;
                }
            }

            const savedTheme = localStorage.getItem(STORAGE_KEYS.theme);
            if (savedTheme) {
                const th = JSON.parse(savedTheme);
                state.themeMode = th.themeMode || 'auto';
                state.customColors = th.customColors || null;
            }
        } catch (e) {}
    }

    function saveState() {
        try {
            trimObjectKeys(state.schedules, 15);
            trimObjectKeys(state.theater, 15);

            localStorage.setItem(STORAGE_KEYS.url, state.url);
            localStorage.setItem(STORAGE_KEYS.key, state.key);
            localStorage.setItem(STORAGE_KEYS.model, state.model);
            localStorage.setItem(STORAGE_KEYS.data, JSON.stringify(state.schedules));
            localStorage.setItem(STORAGE_KEYS.theaterData, JSON.stringify(state.theater));
            localStorage.setItem(STORAGE_KEYS.models, JSON.stringify(state.availableModels));
            localStorage.setItem(STORAGE_KEYS.sysPrompt, state.sysPrompt);
            localStorage.setItem(STORAGE_KEYS.userPrompt, state.userPrompt);
            localStorage.setItem(STORAGE_KEYS.theaterPresets, JSON.stringify(state.theaterPresets));
            localStorage.setItem('sgn_v26_curr_th_preset', state.currentTheaterPresetId);
            localStorage.setItem(STORAGE_KEYS.favTheaters, JSON.stringify(state.favoriteTheaters));
            localStorage.setItem(STORAGE_KEYS.apiLog, JSON.stringify(state.apiLog));
            localStorage.setItem(STORAGE_KEYS.theme, JSON.stringify({ themeMode: state.themeMode, customColors: state.customColors }));
        } catch (e) {
            if (e.name === 'QuotaExceededError') {
                showToast('Bộ nhớ đầy rồi! Tawa đang dọn dẹp bớt đây...', true);
                trimObjectKeys(state.schedules, 5);
                trimObjectKeys(state.theater, 5);
                if (state.favoriteTheaters.length > 100) {
                    state.favoriteTheaters = state.favoriteTheaters.slice(0, 100);
                }
                localStorage.setItem(STORAGE_KEYS.data, JSON.stringify(state.schedules));
                localStorage.setItem(STORAGE_KEYS.theaterData, JSON.stringify(state.theater));
                localStorage.setItem(STORAGE_KEYS.favTheaters, JSON.stringify(state.favoriteTheaters));
            }
        }
    }

