    function normalizeUrl(url) {
        let u = url.trim().replace(/\/+$/, '');
        if (u.endsWith('/v1')) u = u.slice(0, -3);
        return u;
    }

    function getContextInfo() {
        try {
            const ctx = targetWindow.SillyTavern?.getContext?.();
            const chatId = ctx?.chatId || ctx?.characterId || 'default_chat';
            let charName = 'Kẻ Dệt Mộng';
            if (ctx?.characters && ctx?.characterId && ctx.characters[ctx.characterId]) {
                charName = ctx.characters[ctx.characterId].name;
            } else if (ctx?.chatId) {
                charName = ctx.chatId.replace('.jsonl', '');
            }
            let context = '';
            if (ctx && ctx.chat) {
                const messages = ctx.chat.slice(-20);
                context = messages.map(m => `${m.is_user ? '<user>' : '<char>'}: ${m.mes}`).join('\n');
            }
            return { chatId, charName, context };
        } catch (e) {
            return { chatId: 'default_chat', charName: 'Kẻ Dệt Mộng', context: null };
        }
    }

    function escapeHtml(str) {
        if (!str) return '';
        return str.toString().replace(/[&<>]/g, m => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[m]));
    }

    async function injectToInput(text) {
        if (!text) return false;

        try {
            if (typeof triggerSlash === 'function') {
                await triggerSlash('/setinput ' + text);
                return true;
            }
        } catch (error) {
            console.warn('[NHẬT BÁO TAWA] triggerSlash lỗi:', error);
        }

        try {
            const selectors = ['#send_textarea', 'textarea#send_textarea', 'textarea[name="user_input"]', '#chat-input textarea', 'textarea'];
            let inputEl = null;
            selectors.some(selector => {
                const found = Array.from(targetDoc.querySelectorAll(selector)).find(node =>
                    !node.disabled && !node.readOnly && (node.offsetParent !== null || selector === 'textarea')
                );
                if (found) {
                    inputEl = found;
                    return true;
                }
                return false;
            });

            if (!inputEl) return false;

            inputEl.focus();
            if (inputEl.tagName === 'TEXTAREA' || inputEl.tagName === 'INPUT') {
                const proto = inputEl.tagName === 'TEXTAREA'
                    ? targetWindow.HTMLTextAreaElement.prototype
                    : targetWindow.HTMLInputElement.prototype;
                const descriptor = Object.getOwnPropertyDescriptor(proto, 'value');
                if (descriptor?.set) descriptor.set.call(inputEl, text);
                else inputEl.value = text;
            } else if (inputEl.isContentEditable) {
                inputEl.textContent = text;
            }

            inputEl.dispatchEvent(new targetWindow.Event('input', { bubbles: true }));
            inputEl.dispatchEvent(new targetWindow.Event('change', { bubbles: true }));
            return true;
        } catch (error) {
            console.warn('[NHẬT BÁO TAWA] Lỗi nhập khung chat:', error);
            return false;
        }
    }

    function showToast(msg, isError = false) {
        if (destroyed) return;
        let toast = targetDoc.getElementById('sgn-toast-v28');
        if (!toast) {
            toast = targetDoc.createElement('div');
            toast.id = 'sgn-toast-v28';
            targetDoc.body.appendChild(toast);
        }

        toast.textContent = '';
        const icon = targetDoc.createElement('i');
        icon.className = isError ? 'fa-solid fa-triangle-exclamation' : 'fa-solid fa-check-circle';
        const text = targetDoc.createElement('span');
        text.textContent = String(msg || '');
        toast.append(icon, text);

        if (isError) {
            toast.style.borderLeftColor = 'var(--sgn-danger)';
            toast.style.color = 'var(--sgn-danger)';
        } else {
            toast.style.borderLeftColor = 'var(--sgn-accent)';
            toast.style.color = 'var(--sgn-accent)';
        }

        toast.style.transform = 'translate(-50%, -20px)';
        toast.style.opacity = '0';

        runFrame(() => {
            toast.style.opacity = '1';
            toast.style.transform = 'translate(-50%, 0)';
        });
        registerTimeout(() => {
            toast.style.opacity = '0';
            toast.style.transform = 'translate(-50%, -10px)';
        }, 1500);
    }

    async function fetchModels() {
        const u = targetDoc.getElementById('sgn-input-url').value;
        const k = targetDoc.getElementById('sgn-input-key').value;
        if (!u || !k) {
            showToast('Chưa có API URL hay Key kìa 🥺', true);
            return;
        }
        const btn = targetDoc.getElementById('sgn-btn-fetch');
        if (btn) {
            btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Tawa đang tìm model...';
            btn.disabled = true;
        }
        try {
            const base = normalizeUrl(u);
            const res = await trackedFetch(`${base}/v1/models`, {
                headers: { 'Authorization': `Bearer ${k}` }
            });
            if (!res.ok) throw new Error(`Lỗi HTTP: ${res.status}`);
            const data = await res.json();
            const models = (data.data || []).map(item => item.id);
            if (models.length > 0) {
                state.availableModels = models;
                updateModelSelector();
                showToast(`Tuyệt vời! Kéo được ${models.length} model 🌸`);
                saveState();
            } else {
                throw new Error('Không tìm thấy model nào trong List');
            }
        } catch (e) {
            showToast('Lỗi kết nối rồi nha 💦', true);
        } finally {
            if (btn) {
                btn.innerHTML = '<i class="fa-solid fa-cloud-arrow-down"></i> Tải danh sách Model';
                btn.disabled = false;
            }
        }
    }

    async function generateSchedule() {
        const { chatId, context } = getContextInfo();
        if (!state.url || !state.key || !state.model) {
            showToast('Nhập API bên Lõi Hệ Thống trước nha! 🌸', true);
            return;
        }
        if (!context) {
            showToast('Chưa có cốt truyện nào để Tawa dệt hết á 🥺.', true);
            return;
        }

        state.isGeneratingSchedule = true;
        updateButtonState();

        const directionInput = targetDoc.getElementById('sgn-input-direction');
        const direction = directionInput ? directionInput.value.trim() : '';
        const systemPrompt = state.sysPrompt;
        let userPrompt = state.userPrompt.replace('{{context}}', context);
        if (direction) {
            userPrompt += `\n\n【Chỉ thị Đặc biệt từ Kẻ Dệt Mộng】:\n${direction}\nHãy ưu tiên thiết kế lịch trình dựa trên chỉ thị này!`;
        }

        const startTime = Date.now();

        try {
            const base = normalizeUrl(state.url);
            const reqBody = {
                model: state.model,
                messages: [
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ],
                temperature: 0.75
            };

            state.apiLog.schedule.time = new Date().toLocaleString('vi-VN');
            state.apiLog.schedule.req = JSON.stringify(reqBody, null, 2);
            state.apiLog.schedule.status = 'loading';
            saveState();

            const res = await trackedFetch(`${base}/v1/chat/completions`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${state.key}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(reqBody)
            });

            const duration = ((Date.now() - startTime) / 1000).toFixed(1);
            state.apiLog.schedule.duration = duration + 's';

            if (!res.ok) throw new Error(`Lỗi kết nối API: ${res.status}`);
            const data = await res.json();

            state.apiLog.schedule.res = JSON.stringify(data, null, 2);
            state.apiLog.schedule.status = 'success';

            let content = data.choices[0].message.content;
            const jsonMatch = content.match(/\[[\s\S]*\]/);
            if (jsonMatch) content = jsonMatch[0];
            const schedules = JSON.parse(content);
            if (Array.isArray(schedules) && schedules.length) {
                state.schedules[chatId] = schedules;
                saveState();
                showToast('Mực in còn ướt! Lịch trình 7 ngày đã sẵn sàng ✨');
            } else {
                throw new Error('AI trả về JSON sai format rồi');
            }
        } catch (e) {
            showToast('Lỗi Dệt Mộng Lịch Trình, check Log nha 💦', true);
            state.apiLog.schedule.status = 'error';
            state.apiLog.schedule.error = e.message;
            state.apiLog.schedule.duration = ((Date.now() - startTime) / 1000).toFixed(1) + 's';
            saveState();
        } finally {
            state.isGeneratingSchedule = false;
            updateButtonState();
            if (panelEl && panelEl.querySelector('.sgn-tab.active')?.getAttribute('data-tab') === 'schedule') {
                renderSchedules();
            }
        }
    }

    async function generateTheater() {
        const { chatId, context } = getContextInfo();
        if (!state.url || !state.key || !state.model) {
            showToast('Nhập API bên Lõi Hệ Thống trước nha! 🌸', true);
            return;
        }

        const promptInput = targetDoc.getElementById('sgn-input-theater');
        if (promptInput) {
            state.theaterPrompt = promptInput.value;
            const current = state.theaterPresets.find(p => p.id === state.currentTheaterPresetId);
            if (current) current.prompt = state.theaterPrompt;
            saveState();
        }

        state.isGeneratingTheater = true;
        updateButtonState();

        const userPrompt = state.theaterPrompt.replace('{{context}}', context || '(Không có dữ liệu)');
        const startTime = Date.now();

        try {
            const base = normalizeUrl(state.url);
            const reqBody = {
                model: state.model,
                messages: [
                    { role: 'user', content: userPrompt }
                ],
                temperature: 0.8
            };

            state.apiLog.theater.time = new Date().toLocaleString('vi-VN');
            state.apiLog.theater.req = JSON.stringify(reqBody, null, 2);
            state.apiLog.theater.status = 'loading';
            saveState();

            const res = await trackedFetch(`${base}/v1/chat/completions`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${state.key}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(reqBody)
            });

            const duration = ((Date.now() - startTime) / 1000).toFixed(1);
            state.apiLog.theater.duration = duration + 's';

            if (!res.ok) throw new Error(`Lỗi kết nối API: ${res.status}`);
            const data = await res.json();

            state.apiLog.theater.res = JSON.stringify(data, null, 2);
            state.apiLog.theater.status = 'success';

            let content = data.choices[0].message.content;
            content = content.replace(/^```html\n?|^```markdown\n?|^```\n?|\n?```$/gi, '').trim();

            state.theater[chatId] = content;
            saveState();
            showToast('Màn nhung hé mở! Tiểu kịch trường đã sẵn sàng 🎭');
        } catch (e) {
            showToast('Đạo diễn AI nghỉ ốm rồi: ' + e.message, true);
            state.apiLog.theater.status = 'error';
            state.apiLog.theater.error = e.message;
            state.apiLog.theater.duration = ((Date.now() - startTime) / 1000).toFixed(1) + 's';
            saveState();
        } finally {
            state.isGeneratingTheater = false;
            updateButtonState();
            if (panelEl && panelEl.querySelector('.sgn-tab.active')?.getAttribute('data-tab') === 'theater') {
                renderTheater();
            }
        }
    }

    function updateButtonState() {
        const schBtn = targetDoc.getElementById('sgn-btn-generate');
        if (schBtn) {
            if (state.isGeneratingSchedule) {
                schBtn.disabled = true;
                schBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Tawa đang miệt mài viết lịch...';
            } else {
                schBtn.disabled = false;
                schBtn.innerHTML = '<i class="fa-solid fa-wand-magic-sparkles"></i> Dệt Mộng Lịch Trình Mới';
            }
        }
        const thBtn = targetDoc.getElementById('sgn-btn-theater-gen');
        if (thBtn) {
            if (state.isGeneratingTheater) {
                thBtn.disabled = true;
                thBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Đang sắp xếp phông nền...';
            } else {
                thBtn.disabled = false;
                thBtn.innerHTML = '<i class="fa-solid fa-masks-theater"></i> Render Góc Kịch Nhỏ';
            }
        }
    }

    function renderSchedules() {
        const container = targetDoc.getElementById('sgn-schedule-list');
        const empty = targetDoc.getElementById('sgn-empty-state');
        const batchBar = targetDoc.getElementById('sgn-batch-bar');
        if (!container || !empty) return;

        const { chatId, charName } = getContextInfo();
        const list = state.schedules[chatId] || [];
        if (list.length > 0) {
            empty.style.display = 'none';
            container.style.display = 'flex';
            if (batchBar) batchBar.style.display = 'flex';

            container.innerHTML = `<div class="sgn-char-badge"><i class="fa-solid fa-star"></i> FOCUS: ${escapeHtml(charName)}</div>`;
            cleanupDetachedListeners();
            list.forEach((dayItem, dIdx) => {
                const article = targetDoc.createElement('div');
                article.className = 'sgn-day-block collapsed'; 

                let eventsHtml = '';
                if (Array.isArray(dayItem.events)) {
                    dayItem.events.forEach((evt, eIdx) => {
                        eventsHtml += `
                            <div class="sgn-event-card">
                                <div class="sgn-event-meta">
                                    <span style="display:flex; gap:12px; align-items:center;">
                                        <span style="color: var(--sgn-accent); font-size: 13px;"><i class="fa-regular fa-clock"></i> ${escapeHtml(evt.time)}</span>
                                        <span><i class="fa-solid fa-location-dot"></i> ${escapeHtml(evt.location)}</span>
                                    </span>
                                    <label class="sgn-checkbox-label">
                                        <input type="checkbox" class="sgn-evt-check" data-didx="${dIdx}" data-eidx="${eIdx}">
                                        Duyệt ✅
                                    </label>
                                </div>
                                <div class="sgn-event-title">${escapeHtml(evt.title)}</div>
                                <p class="sgn-event-desc">${escapeHtml(evt.user_action)}</p>
                                <div class="sgn-char-action"><i class="fa-solid fa-paw"></i> Động thái ẩn: ${escapeHtml(evt.npc_action || evt.char_action)}</div>
                                <div class="sgn-action-box">
                                    <button class="sgn-link sgn-single-link" data-didx="${dIdx}" data-eidx="${eIdx}">
                                        <i class="fa-solid fa-feather-pointed"></i> Nạp vào Khung Chat
                                    </button>
                                </div>
                            </div>
                        `;
                    });
                }

                const xiaodayHtml = dayItem.xiaoday_comment ? `<div class="sgn-xiaoday"><i class="fa-solid fa-comment-medical"></i> Tawa bình luận: ${escapeHtml(dayItem.xiaoday_comment)}</div>` : '';

                article.innerHTML = `
                    <div class="sgn-day-title">
                        <span><i class="fa-solid fa-chevron-down sgn-fold-icon" style="margin-right:8px;font-size:15px; color: var(--sgn-accent);"></i>${escapeHtml(dayItem.day || `Ngày thứ ${dIdx + 1}`)}</span>
                        <span class="sgn-weather"><i class="fa-solid fa-cloud-sun"></i> ${escapeHtml(dayItem.weather || '')}</span>
                    </div>
                    <div class="sgn-day-content">
                        ${eventsHtml}
                        ${xiaodayHtml}
                    </div>
                `;
                container.appendChild(article);

                const titleEl = article.querySelector('.sgn-day-title');
                addListener(titleEl, 'click', () => {
                    article.classList.toggle('collapsed');
                });
            });

            targetDoc.querySelectorAll('.sgn-single-link').forEach(btn => {
                addListener(btn, 'click', async function() {
                    const dIdx = parseInt(this.getAttribute('data-didx'), 10);
                    const eIdx = parseInt(this.getAttribute('data-eidx'), 10);
                    const dayItem = list[dIdx];
                    const evt = dayItem?.events?.[eIdx];
                    if (dayItem && evt) {
                        const text = `- Vào lúc [${evt.time}, ${dayItem.day}] tại [${evt.location}]: Khởi chạy sự kiện "${evt.title}".\n> Nội dung: ${evt.user_action}\n> [Tài liệu ẩn] NPC: ${evt.npc_action || evt.char_action}`;
                        const ok = await injectToInput(text);
                        showToast(ok ? 'Đã nạp sự kiện vào khung chat 🌸' : 'Chưa tìm thấy khung chat nè 💦', !ok);
                        if (ok) closePanel();
                    }
                });
            });
        } else {
            empty.style.display = 'block';
            container.style.display = 'none';
            if (batchBar) batchBar.style.display = 'none';
        }
        updateButtonState();
    }

    function renderTheater() {
        const output = targetDoc.getElementById('sgn-theater-output');
        if (!output) return;
        const { chatId } = getContextInfo();
        const content = state.theater[chatId];
        const favBtn = targetDoc.getElementById('sgn-btn-theater-fav');

        if (content) {
            output.innerHTML = content;
            if (favBtn) {
                favBtn.style.display = 'flex';
                favBtn.onclick = () => {
                    const title = prompt('Kẻ Dệt Mộng đặt tên cho phân cảnh này nha:', 'Một ngày đáng nhớ');
                    if (title === null) return;

                    const { charName } = getContextInfo();
                    state.favoriteTheaters.unshift({
                        id: 'fav_' + Date.now(),
                        charName: charName,
                        title: title,
                        time: new Date().toLocaleString('vi-VN'),
                        content: content
                    });
                    if (state.favoriteTheaters.length > 100) {
                        state.favoriteTheaters.pop();
                    }
                    saveState();
                    showToast('Đã cất đoạn kịch này vào Kho Lưu Trữ 💖');
                };
            }
        } else {
            output.innerHTML = '<div class="sgn-empty">Sân khấu đang trống, mau bấm nút Render đi nè ✨</div>';
            if (favBtn) favBtn.style.display = 'none';
        }
        updateButtonState();
    }

    function renderFavoriteTheaters() {
        const container = targetDoc.getElementById('sgn-fav-list');
        if (!container) return;
        if (!state.favoriteTheaters || state.favoriteTheaters.length === 0) {
            container.innerHTML = '<div class="sgn-empty">Trống trơn! Kẻ Dệt Mộng chưa lưu gì hết á 🥺</div>';
            cleanupDetachedListeners();
            return;
        }
        container.innerHTML = '';
        cleanupDetachedListeners();

        const groups = {};
        state.favoriteTheaters.forEach((fav, idx) => {
            const cName = fav.charName || 'Nhân vật vô danh';
            if (!groups[cName]) groups[cName] = [];
            groups[cName].push({ ...fav, idx });
        });

        for (const [charName, favs] of Object.entries(groups)) {
            const groupEl = targetDoc.createElement('div');
            groupEl.className = 'sgn-fav-group';

            let itemsHtml = '';
            favs.forEach(f => {
                itemsHtml += `
                    <div class="sgn-event-card" style="margin-top:12px; box-shadow: 0 4px 10px rgba(0,0,0,0.05);">
                        <div class="sgn-event-meta" style="cursor:pointer;" data-toggle-id="${f.id}">
                            <span style="font-weight:800; color:var(--sgn-accent); font-size:14px;"><i class="fa-solid fa-masks-theater"></i> ${escapeHtml(f.title || 'Vô danh')}</span>
                            <span>${escapeHtml(f.time)} <i class="fa-solid fa-chevron-down" style="margin-left:6px;"></i></span>
                        </div>
                        <div id="fav-content-${f.id}" class="sgn-theater-render" style="display:none; min-height:auto; max-height:350px; padding:15px; margin-top:12px; border-radius:8px;">
                            ${f.content}
                        </div>
                        <div class="sgn-action-box" style="margin-top:12px; border-top:none;">
                            <button class="sgn-btn sgn-btn-outline sgn-fav-del" data-id="${f.id}" style="width:auto; padding:6px 14px; margin:0; color:var(--sgn-danger); border-color:var(--sgn-danger); font-size:12px;"><i class="fa-solid fa-trash-can"></i> Thùng rác</button>
                        </div>
                    </div>
                `;
            });

            groupEl.innerHTML = `
                <div class="sgn-fav-header" style="background:var(--sgn-card); border:2px dashed var(--sgn-border); padding:12px 16px; border-radius:8px; font-weight:800; cursor:pointer; display:flex; justify-content:space-between; margin-bottom:10px; color: var(--sgn-ink);">
                    <span><i class="fa-solid fa-folder-open" style="color:var(--sgn-accent); margin-right:6px;"></i> ${escapeHtml(charName)} (${favs.length} mục)</span>
                    <i class="fa-solid fa-chevron-down sgn-fold-icon" style="transform:rotate(-90deg); color:var(--sgn-accent);"></i>
                </div>
                <div class="sgn-fav-content" style="display:none; padding-left:15px; border-left:3px solid var(--sgn-border); margin-bottom:20px;">
                    ${itemsHtml}
                </div>
            `;
            container.appendChild(groupEl);

            const header = groupEl.querySelector('.sgn-fav-header');
            const content = groupEl.querySelector('.sgn-fav-content');
            addListener(header, 'click', () => {
                const isHidden = content.style.display === 'none';
                content.style.display = isHidden ? 'block' : 'none';
                header.querySelector('.sgn-fold-icon').style.transform = isHidden ? 'rotate(0deg)' : 'rotate(-90deg)';
            });

            groupEl.querySelectorAll('.sgn-event-meta').forEach(meta => {
                addListener(meta, 'click', function() {
                    const id = this.getAttribute('data-toggle-id');
                    const targetContent = targetDoc.getElementById(`fav-content-${id}`);
                    if (targetContent) {
                        const isHidden = targetContent.style.display === 'none';
                        targetContent.style.display = isHidden ? 'block' : 'none';
                        this.querySelector('.fa-chevron-down, .fa-chevron-up').className = isHidden ? 'fa-solid fa-chevron-up' : 'fa-solid fa-chevron-down';
                    }
                });
            });
        }

        targetDoc.querySelectorAll('.sgn-fav-del').forEach(btn => {
            addListener(btn, 'click', function() {
                const id = this.getAttribute('data-id');
                if (confirm('Kẻ Dệt Mộng muốn ném đoạn này vào thùng rác thật hả? 🥺')) {
                    state.favoriteTheaters = state.favoriteTheaters.filter(f => f.id !== id);
                    saveState();
                    renderFavoriteTheaters();
                    showToast('Đã xóa thành công!');
                }
            });
        });
    }

    function updateModelSelector() {
        const select = targetDoc.getElementById('sgn-select-model');
        const input = targetDoc.getElementById('sgn-input-model');
        if (!select || !input) return;

        select.innerHTML = '<option value="">-- Mở danh sách Model --</option>';
        let found = false;
        (state.availableModels || []).forEach(m => {
            const opt = targetDoc.createElement('option');
            opt.value = m;
            opt.innerText = m;
            select.appendChild(opt);
            if (m === state.model) found = true;
        });

        if (state.model && !found) {
            const opt = targetDoc.createElement('option');
            opt.value = state.model;
            opt.innerText = state.model + ' (Tự nhập)';
            select.appendChild(opt);
        }
        select.value = state.model;
        input.value = state.model;
    }

    function updateTheaterPresetsUI() {
        const select = targetDoc.getElementById('sgn-th-preset-select');
        const textarea = targetDoc.getElementById('sgn-input-theater');
        if (!select || !textarea) return;

        select.innerHTML = '';
        state.theaterPresets.forEach(p => {
            const opt = targetDoc.createElement('option');
            opt.value = p.id;
            opt.innerText = p.name;
            select.appendChild(opt);
        });
        select.value = state.currentTheaterPresetId;

        const current = state.theaterPresets.find(p => p.id === state.currentTheaterPresetId);
        if (current) {
            textarea.value = current.prompt;
            state.theaterPrompt = current.prompt;
        }
    }

