        const theaterHtml = `
            <div style="display:flex; flex-direction:column; height:100%;">
                <label class="sgn-label">Preset Phông Nền / Văn Phong</label>
                <div style="display:flex; gap:10px; margin-bottom: 16px;">
                    <select id="sgn-th-preset-select" class="sgn-select" style="margin-bottom:0; flex:1;"></select>
                    <button id="sgn-btn-save-th-preset" class="sgn-btn sgn-btn-outline" style="margin-bottom:0; width:auto; padding:0 16px;" title="Lưu thành Preset mới"><i class="fa-solid fa-floppy-disk"></i></button>
                    <button id="sgn-btn-del-th-preset" class="sgn-btn sgn-btn-outline" style="margin-bottom:0; width:auto; padding:0 16px; color:var(--sgn-danger); border-color:var(--sgn-danger);" title="Xóa Preset này"><i class="fa-solid fa-trash-can"></i></button>
                </div>
                <label class="sgn-label">Lệnh đạo diễn (Dùng {{context}} để chèn Chat cũ)</label>
                <textarea id="sgn-input-theater" class="sgn-textarea" rows="6" placeholder="Kẻ Dệt Mộng gõ kịch bản vào đây nè..."></textarea>
                <button id="sgn-btn-theater-gen" class="sgn-btn" style="margin-top:10px;">
                    <i class="fa-solid fa-masks-theater"></i> Render Góc Kịch Nhỏ
                </button>
                <div id="sgn-theater-output" class="sgn-theater-render" style="margin-top:16px;"></div>
                <button id="sgn-btn-theater-fav" class="sgn-btn sgn-btn-outline" style="margin-top:16px; display:none;">
                    <i class="fa-solid fa-heart"></i> Cất vào Kho Lưu Trữ
                </button>
            </div>
        `;

        const favTheaterHtml = `
            <div>
                <p style="font-size:12px; color:var(--sgn-accent); font-weight: 700; margin-bottom:16px; text-align:center; background: rgba(255,126,179,0.1); padding: 8px; border-radius: 8px;">Tawa sẽ giữ dùm tối đa 100 kịch bản yêu thích nha! 🌸</p>
                <div id="sgn-fav-list" style="display:flex; flex-direction:column; gap:15px;"></div>
            </div>
        `;

        const promptHtml = `
            <div>
                <label class="sgn-label">Luật Kiến Tạo Lịch Trình (System Prompt)</label>
                <textarea id="sgn-input-sys" class="sgn-textarea" rows="9"></textarea>
                <label class="sgn-label">Định Dạng Bắt Buộc (User Prompt)</label>
                <textarea id="sgn-input-user" class="sgn-textarea" rows="7"></textarea>
                <p style="font-size:12px; color:var(--sgn-accent); font-weight:bold; margin-bottom:16px;">Lưu ý: Không được xóa chữ {{context}} đâu nha! 🐾</p>
                <div style="display:flex; gap:12px;">
                    <button id="sgn-btn-reset-prompt" class="sgn-btn sgn-btn-outline">
                        <i class="fa-solid fa-arrow-rotate-left"></i> Reset Mặc Định
                    </button>
                    <button id="sgn-btn-save-prompt" class="sgn-btn">
                        <i class="fa-solid fa-check-double"></i> Chốt Lệnh
                    </button>
                </div>
            </div>
        `;

        const logHtml = `
            <div>
                ${buildLogSection('【Log: Lịch Trình Tương Lai】', state.apiLog.schedule)}
                ${buildLogSection('【Log: Render Góc Kịch Nhỏ】', state.apiLog.theater)}
            </div>
        `;

        const container = targetDoc.getElementById('sgn-tab-content');
        if (!container || destroyed) return;

        if (tabId === 'api') container.innerHTML = apiHtml;
        else if (tabId === 'schedule') container.innerHTML = scheduleHtml;
        else if (tabId === 'theater') container.innerHTML = theaterHtml;
        else if (tabId === 'fav_theater') container.innerHTML = favTheaterHtml;
        else if (tabId === 'prompt') container.innerHTML = promptHtml;
        else if (tabId === 'log') container.innerHTML = logHtml;
        cleanupDetachedListeners();

        if (tabId === 'api') {
            const u = targetDoc.getElementById('sgn-input-url');
            const k = targetDoc.getElementById('sgn-input-key');

            if (u) u.value = state.url;
            if (k) k.value = state.key;

            updateModelSelector();

            const sel = targetDoc.getElementById('sgn-select-model');
            if (sel) {
                addListener(sel, 'change', () => {
                    if (sel.value) {
                        targetDoc.getElementById('sgn-input-model').value = sel.value;
                        state.model = sel.value;
                    }
                });
            }

            const customBtn = targetDoc.getElementById('sgn-btn-custom-model');
            if (customBtn) {
                addListener(customBtn, 'click', () => {
                    const customModel = prompt('Tên Model lạ Kẻ Dệt Mộng muốn dùng là gì?', state.model);
                    if (customModel && customModel.trim()) {
                        state.model = customModel.trim();
                        saveState();
                        updateModelSelector();
                        showToast('Đã nhét tên Model mới vào hệ thống');
                    }
                });
            }

            const fetchBtn = targetDoc.getElementById('sgn-btn-fetch');
            if (fetchBtn) addListener(fetchBtn, 'click', fetchModels);

            const saveBtn = targetDoc.getElementById('sgn-btn-save-api');
            if (saveBtn) {
                addListener(saveBtn, 'click', () => {
                    state.url = u.value;
                    state.key = k.value;
                    state.model = targetDoc.getElementById('sgn-input-model').value || state.model;
                    saveState();
                    showToast('Đã cất kỹ Chìa Khóa API 💖');
                });
            }

            const destroyBtn = targetDoc.getElementById('sgn-btn-destroy');
            if (destroyBtn) {
                addListener(destroyBtn, 'click', () => {
                    destroyApp();
                });
            }
        } else if (tabId === 'prompt') {
            const sInput = targetDoc.getElementById('sgn-input-sys');
            const uInput = targetDoc.getElementById('sgn-input-user');
            if (sInput) sInput.value = state.sysPrompt;
            if (uInput) uInput.value = state.userPrompt;

            const savePBtn = targetDoc.getElementById('sgn-btn-save-prompt');
            if (savePBtn) {
                addListener(savePBtn, 'click', () => {
                    state.sysPrompt = sInput.value;
                    state.userPrompt = uInput.value;
                    saveState();
                    showToast('Cập nhật mã lệnh thành công ✨');
                });
            }
            const resetBtn = targetDoc.getElementById('sgn-btn-reset-prompt');
            if (resetBtn) {
                addListener(resetBtn, 'click', () => {
                    sInput.value = DEFAULT_SYS_PROMPT;
                    uInput.value = DEFAULT_USER_PROMPT;
                    state.sysPrompt = DEFAULT_SYS_PROMPT;
                    state.userPrompt = DEFAULT_USER_PROMPT;
                    saveState();
                    showToast('Đã xóa sạch chỉnh sửa, đưa về nguyên thủy');
                });
            }
        } else if (tabId === 'schedule') {
            const genBtn = targetDoc.getElementById('sgn-btn-generate');
            if (genBtn) addListener(genBtn, 'click', generateSchedule);
            renderSchedules();

            const batchBtn = targetDoc.getElementById('sgn-btn-batch-send');
            if (batchBtn) {
                addListener(batchBtn, 'click', async () => {
                    const checks = targetDoc.querySelectorAll('.sgn-evt-check:checked');
                    if (checks.length === 0) return showToast('Bạn chưa tick ô nào kìa 🥺', true);

                    const { chatId } = getContextInfo();
                    const list = state.schedules[chatId] || [];
                    let combinedText = '[Chỉ thị Tối cao]: Hãy đẩy dòng thời gian để diễn ra chuỗi sự kiện sau:\n\n';

                    checks.forEach(c => {
                        const dIdx = parseInt(c.getAttribute('data-didx'), 10);
                        const eIdx = parseInt(c.getAttribute('data-eidx'), 10);
                        const dayItem = list[dIdx];
                        const evt = dayItem?.events?.[eIdx];
                        if (dayItem && evt) {
                            combinedText += `- Vào lúc [${evt.time}, ${dayItem.day}] tại [${evt.location}]: Tiến hành sự kiện "${evt.title}".\n> Nội dung chính: ${evt.user_action}\n> [Tài liệu ẩn] Hành động NPC: ${evt.npc_action || evt.char_action}\n\n`;
                        }
                    });

                    if (combinedText) {
                        const ok = await injectToInput(combinedText.trim());
                        showToast(ok ? `Đã nạp ${checks.length} sự kiện vào Khung Chat 🌸` : 'Lỗi gửi chữ, không thấy khung chat!', !ok);
                        if (ok) closePanel();
                    }
                });
            }
        } else if (tabId === 'theater') {
            updateTheaterPresetsUI();

            const thSelect = targetDoc.getElementById('sgn-th-preset-select');
            if (thSelect) {
                addListener(thSelect, 'change', () => {
                    state.currentTheaterPresetId = thSelect.value;
                    updateTheaterPresetsUI();
                    saveState();
                });
            }

            const thTextarea = targetDoc.getElementById('sgn-input-theater');
            if (thTextarea) {
                addListener(thTextarea, 'input', () => {
                    const current = state.theaterPresets.find(p => p.id === state.currentTheaterPresetId);
                    if (current) {
                        current.prompt = thTextarea.value;
                        saveState();
                    }
                });
            }

            const saveThBtn = targetDoc.getElementById('sgn-btn-save-th-preset');
            if (saveThBtn) {
                addListener(saveThBtn, 'click', () => {
                    const name = prompt('Đặt tên cho Preset mới này nha:');
                    if (!name) return;
                    const promptText = thTextarea.value;
                    const newId = 'th_preset_' + Date.now();
                    state.theaterPresets.push({ id: newId, name: name, prompt: promptText });
                    state.currentTheaterPresetId = newId;
                    saveState();
                    updateTheaterPresetsUI();
                    showToast('Đã lưu Preset mới thành công!');
                });
            }

            const delThBtn = targetDoc.getElementById('sgn-btn-del-th-preset');
            if (delThBtn) {
                addListener(delThBtn, 'click', () => {
                    if (state.currentTheaterPresetId === 'default') {
                        return showToast('Cái Mặc định này không xóa được đâu 🥺', true);
                    }
                    if (confirm('Kẻ Dệt Mộng chắc chắn muốn vứt Preset này đi hả?')) {
                        state.theaterPresets = state.theaterPresets.filter(p => p.id !== state.currentTheaterPresetId);
                        state.currentTheaterPresetId = 'default';
                        saveState();
                        updateTheaterPresetsUI();
                        showToast('Đã vứt vào sọt rác 🗑️');
                    }
                });
            }

            const genThBtn = targetDoc.getElementById('sgn-btn-theater-gen');
            if (genThBtn) addListener(genThBtn, 'click', generateTheater);
            renderTheater();
        } else if (tabId === 'fav_theater') {
            renderFavoriteTheaters();
        }
    }

    function openPanel() {
        if (!panelEl) return;
        const activeTab = panelEl.querySelector('.sgn-tab.active');
        if (activeTab) {
            const tid = activeTab.getAttribute('data-tab');
            if (tid === 'schedule') renderSchedules();
            else if (tid === 'theater') renderTheater();
        }
        panelEl.classList.add('show');
        runFrame(() => {
            if (panelEl) panelEl.classList.add('visible');
        });
    }

    function closePanel() {
        if (!panelEl) return;
        panelEl.classList.remove('visible');
        registerTimeout(() => {
            if (panelEl && !panelEl.classList.contains('visible')) {
                panelEl.classList.remove('show');
            }
        }, 300);
    }

    const onPointerMoveFn = (e) => {
        if (!isDragging || !ballEl) return;
        const dx = e.clientX - dragStartX;
        const dy = e.clientY - dragStartY;
        if (Math.abs(dx) > 8 || Math.abs(dy) > 8) {
            hasMoved = true;
        }
        if (hasMoved) {
            let newX = ballStartX + dx;
            let newY = ballStartY + dy;
            const ballSize = 56;
            newX = Math.max(0, Math.min(newX, targetWindow.innerWidth - ballSize));
            newY = Math.max(0, Math.min(newY, targetWindow.innerHeight - ballSize));
            ballEl.style.left = newX + 'px';
            ballEl.style.top = newY + 'px';
        }
    };

    const onPointerUpFn = (e) => {
        if (!isDragging) return;
        isDragging = false;
        if (ballEl) {
            ballEl.style.transform = '';
            if (hasMoved) {
                saveBallPosition(ballEl.offsetLeft, ballEl.offsetTop);
            } else {
                openPanel();
            }
        }
    };

    const onResizeFn = () => {
        if (isDragging || !ballEl) return;
        const ballSize = 56;
        let curX = parseInt(ballEl.style.left) || 0;
        let curY = parseInt(ballEl.style.top) || 0;
        const maxX = targetWindow.innerWidth - ballSize;
        const maxY = targetWindow.innerHeight - ballSize;
        curX = Math.max(0, Math.min(curX, maxX));
        curY = Math.max(0, Math.min(curY, maxY));
        ballEl.style.left = curX + 'px';
        ballEl.style.top = curY + 'px';
        saveBallPosition(curX, curY);
    };

    function createFloatBall() {
        const ballSize = 56;
        let initX = targetWindow.innerWidth - ballSize - 25;
        let initY = targetWindow.innerHeight - ballSize - Math.floor(targetWindow.innerHeight * 0.3);
        if (state.ballX !== null && state.ballY !== null && !isNaN(state.ballX) && !isNaN(state.ballY)) {
            initX = Math.max(0, Math.min(state.ballX, targetWindow.innerWidth - ballSize));
            initY = Math.max(0, Math.min(state.ballY, targetWindow.innerHeight - ballSize));
        }
        const ball = targetDoc.createElement('div');
        ball.id = 'sgn-ball-v28';

        // TAWA SVG ICON 🌸✨
        ball.innerHTML = `
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64" fill="none" style="width:30px; height:30px; filter: drop-shadow(0 2px 4px rgba(0,0,0,0.3));">
                <path d="M32 10C35 25 45 28 54 32C45 36 35 39 32 54C29 39 19 36 10 32C19 28 29 25 32 10Z" fill="#ffffff"/>
                <circle cx="16" cy="16" r="4" fill="#ffffff" opacity="0.8"/>
                <circle cx="48" cy="48" r="5" fill="#ffffff" opacity="0.9"/>
                <path d="M25 45 L30 40 L28 48 Z" fill="#ffffff" opacity="0.7"/>
            </svg>
        `;

        ball.style.left = initX + 'px';
        ball.style.top = initY + 'px';
        targetDoc.body.appendChild(ball);
        ballEl = ball;
        applyThemeVars();

        addListener(ball, 'pointerdown', (e) => {
            if (e.pointerType === 'mouse' && e.button !== 0) return;
            e.preventDefault();
            isDragging = true;
            hasMoved = false;
            dragStartX = e.clientX;
            dragStartY = e.clientY;
            ballStartX = ballEl.offsetLeft;
            ballStartY = ballEl.offsetTop;
            ballEl.style.transform = 'scale(0.9)';
        });

        addListener(targetWindow, 'pointermove', onPointerMoveFn);
        addListener(targetWindow, 'pointerup', onPointerUpFn);
        addListener(targetWindow, 'resize', onResizeFn);
    }

    injectStyles();
    loadState();
    createUI();
    createFloatBall();
    console.log('[NHẬT BÁO TAWA] Hệ thống Tawa V28 đã nạp năng lượng xong! 🌸✨');
})();
